/// Compact spec for LLM consumption. The file is regenerated by `build.rs` from `SPEC.md`
/// whenever `SPEC.md` changes, and is git-tracked so it has a stable raw URL on GitHub.
fn compact_spec() -> &'static str {
    include_str!("../ai.txt")
}

// ── `ilo tools` subcommand ─────────────────────────────────────────────────

#[derive(Clone, Copy, PartialEq, Eq)]
enum ToolsOutputFmt {
    Human, // human-readable table (default)
    Ilo,   // valid Decl::Tool ilo syntax
    Json,  // JSON array
}

/// Load and display tool signatures from MCP / HTTP sources.  Returns exit code.
fn tools_cmd(args: &[String]) -> i32 {
    let mut mcp_path: Option<String> = None;
    let mut http_path: Option<String> = None;
    let mut fmt = ToolsOutputFmt::Human;
    let mut full = false;
    let mut graph = false;

    let mut i = 0;
    while i < args.len() {
        match args[i].as_str() {
            "--mcp" | "-m" => {
                if i + 1 >= args.len() {
                    eprintln!("error: --mcp requires a path");
                    return 1;
                }
                mcp_path = Some(args[i + 1].clone());
                i += 2;
            }
            "--tools" | "-t" => {
                if i + 1 >= args.len() {
                    eprintln!("error: --tools requires a path");
                    return 1;
                }
                http_path = Some(args[i + 1].clone());
                i += 2;
            }
            "--human" => {
                fmt = ToolsOutputFmt::Human;
                i += 1;
            }
            "--ilo" => {
                fmt = ToolsOutputFmt::Ilo;
                i += 1;
            }
            "--json" => {
                fmt = ToolsOutputFmt::Json;
                i += 1;
            }
            "--full" | "-f" => {
                full = true;
                i += 1;
            }
            "--graph" | "-g" => {
                graph = true;
                i += 1;
            }
            _ => {
                eprintln!("unknown flag: {}", args[i]);
                eprintln!(
                    "Usage: ilo tools [-m <path>] [-t <path>] \
                     [--human|--ilo|--json] [--full] [--graph]"
                );
                return 1;
            }
        }
    }

    if mcp_path.is_none() && http_path.is_none() {
        eprintln!("error: ilo tools requires at least one of --mcp <path> or --tools <path>");
        eprintln!(
            "Usage: ilo tools [--mcp <path>] [--tools <path>] \
             [--human|--ilo|--json] [--full] [--graph]"
        );
        return 1;
    }

    // --ilo, --json, and --graph always show full signatures.
    if matches!(fmt, ToolsOutputFmt::Ilo | ToolsOutputFmt::Json) || graph {
        full = true;
    }

    // ── HTTP tools (sync, no feature gate) ───────────────────────────────────
    let mut http_names: Vec<String> = Vec::new();
    if let Some(ref path) = http_path {
        let config = match tools::http_provider::ToolsConfig::from_file(path) {
            Ok(c) => c,
            Err(e) => {
                eprintln!("{}", e);
                return 1;
            }
        };
        let mut names: Vec<String> = config.tools.keys().cloned().collect();
        names.sort();
        http_names = names;
    }

    // ── MCP tools (async, feature-gated) ─────────────────────────────────────
    let mcp_decls = match collect_mcp_tool_decls(mcp_path.as_deref()) {
        Ok(d) => d,
        Err(e) => {
            eprintln!("{}", e);
            return 1;
        }
    };

    // ── Render ────────────────────────────────────────────────────────────────
    match fmt {
        ToolsOutputFmt::Human => {
            for name in &http_names {
                if full {
                    println!("{:<32} (http tool — no type info)", name);
                } else {
                    println!("{}", name);
                }
            }
            for decl in &mcp_decls {
                if let ast::Decl::Tool {
                    name,
                    description,
                    params,
                    return_type,
                    ..
                } = decl
                {
                    if full {
                        let sig = tool_sig_str(params, return_type);
                        println!("{:<32} {:<44} {}", name, description, sig);
                    } else {
                        println!("{}", name);
                    }
                }
            }
        }
        ToolsOutputFmt::Ilo => {
            for name in &http_names {
                // No type info: emit with empty description and generic R t t.
                println!("tool {}\"\" > R t t", name);
            }
            for decl in &mcp_decls {
                println!(
                    "{}",
                    codegen::fmt::format_decl(decl, codegen::fmt::FmtMode::Dense)
                );
            }
        }
        ToolsOutputFmt::Json => {
            let mut items: Vec<serde_json::Value> = Vec::new();
            for name in &http_names {
                items.push(serde_json::json!({
                    "name": name,
                    "source": "http",
                    "description": null,
                    "params": [],
                    "return": null
                }));
            }
            for decl in &mcp_decls {
                if let ast::Decl::Tool {
                    name,
                    description,
                    params,
                    return_type,
                    ..
                } = decl
                {
                    let params_json: Vec<serde_json::Value> = params
                        .iter()
                        .map(|p| {
                            serde_json::json!({
                                "name": p.name,
                                "type": codegen::fmt::type_str(&p.ty)
                            })
                        })
                        .collect();
                    items.push(serde_json::json!({
                        "name": name,
                        "source": "mcp",
                        "description": description,
                        "params": params_json,
                        "return": codegen::fmt::type_str(return_type)
                    }));
                }
            }
            match serde_json::to_string_pretty(&items) {
                Ok(s) => println!("{}", s),
                Err(e) => {
                    eprintln!("failed to render JSON: {}", e);
                    return 1;
                }
            }
        }
    }

    // ── Graph (additive — shown after or instead of table) ───────────────────
    if graph {
        print_tool_graph(&mcp_decls);
    }

    0
}

/// Print a type-level composition graph: for each tool, which tools can consume its output.
fn print_tool_graph(decls: &[ast::Decl]) {
    // Collect (name, params, return_type) for all typed tools.
    let tools: Vec<(&str, &[ast::Param], &ast::Type)> = decls
        .iter()
        .filter_map(|d| {
            if let ast::Decl::Tool {
                name,
                params,
                return_type,
                ..
            } = d
            {
                Some((name.as_str(), params.as_slice(), return_type))
            } else {
                None
            }
        })
        .collect();

    if tools.is_empty() {
        println!("(no typed tools — graph requires MCP source)");
        return;
    }

    // Name column width.
    let name_w = tools
        .iter()
        .map(|(n, _, _)| n.len())
        .max()
        .unwrap_or(8)
        .max(8);
    // Sig column width — cap at 36 for readability.
    let sig_w: usize = 36;

    println!("Tool composition graph\n");
    println!("{:<name_w$}  {:<sig_w$}  feeds →", "tool", "signature");
    println!("{}", "─".repeat(name_w + 2 + sig_w + 2 + 40));

    for &(src_name, src_params, src_ret) in &tools {
        let sig = tool_sig_str(src_params, src_ret);
        // The "output" is the ok branch of R, or the type itself.
        let out_ty = tool_ok_type(src_ret);

        // Find tools whose first param (or any param) accepts out_ty.
        let mut consumers: Vec<&str> = tools
            .iter()
            .filter(|&&(dst_name, dst_params, _)| {
                dst_name != src_name
                    && dst_params
                        .iter()
                        .any(|p| types_pipe_compatible(out_ty, &p.ty))
            })
            .map(|&(n, _, _)| n)
            .collect();
        consumers.sort();

        let feeds = if consumers.is_empty() {
            "—".to_string()
        } else {
            consumers.join(", ")
        };

        let sig_char_len = sig.chars().count();
        let sig_display = if sig_char_len > sig_w {
            let truncated: String = sig.chars().take(sig_w.saturating_sub(1)).collect();
            format!("{}…", truncated)
        } else {
            sig
        };
        println!("{:<name_w$}  {:<sig_w$}  {}", src_name, sig_display, feeds);
    }
    println!();
}

/// Unwrap `R ok err` → `ok`; otherwise return the type itself.
fn tool_ok_type(ty: &ast::Type) -> &ast::Type {
    if let ast::Type::Result(ok, _) = ty {
        ok
    } else {
        ty
    }
}

/// True if a value of type `out` can be piped into a parameter of type `param`.
/// Intentionally permissive: unknown/named types match anything.
fn types_pipe_compatible(out: &ast::Type, param: &ast::Type) -> bool {
    use ast::Type::*;
    // Unwrap Optional on the param side — Optional(T) accepts T.
    let param = if let Optional(inner) = param {
        inner
    } else {
        param
    };
    match (out, param) {
        // Named / unknown / Any types — treat as wildcard.
        (Named(_), _) | (_, Named(_)) | (Any, _) | (_, Any) => true,
        // Exact matches.
        (Number, Number) | (Text, Text) | (Bool, Bool) => true,
        // List element type must match.
        (List(a), List(b)) => types_pipe_compatible(a, b),
        // Map — key and value types must match.
        (Map(ak, av), Map(bk, bv)) => {
            types_pipe_compatible(ak, bk) && types_pipe_compatible(av, bv)
        }
        // Result ok branch feeds a result-accepting param.
        (Result(ao, ae), Result(bo, be)) => {
            types_pipe_compatible(ao, bo) && types_pipe_compatible(ae, be)
        }
        // Sum types are text at runtime — compatible with text params.
        (Sum(_), Text) | (Text, Sum(_)) | (Sum(_), Sum(_)) => true,
        _ => false,
    }
}

/// Format params + return type as a human-readable signature string.
fn tool_sig_str(params: &[ast::Param], ret: &ast::Type) -> String {
    let ps: Vec<String> = params
        .iter()
        .map(|p| format!("{}:{}", p.name, codegen::fmt::type_str(&p.ty)))
        .collect();
    if ps.is_empty() {
        format!("> {}", codegen::fmt::type_str(ret))
    } else {
        format!("{} > {}", ps.join(" "), codegen::fmt::type_str(ret))
    }
}

// ── `ilo graph` subcommand ────────────────────────────────────────────────

/// Analyze a program's dependency graph and output JSON / DOT.  Returns exit code.
fn graph_cmd(args: &[String]) -> i32 {
    if args.is_empty() {
        eprintln!(
            "Usage: ilo graph <file> [--fn NAME] [--reverse] [--subgraph] [--budget N] [--dot]"
        );
        return 1;
    }

    let file = &args[0];
    let source = match std::fs::read_to_string(file) {
        Ok(s) => s,
        Err(e) => {
            eprintln!("Error reading {}: {}", file, e);
            return 1;
        }
    };

    let tokens = match lexer::lex(&source) {
        Ok(t) => t,
        Err(e) => {
            eprintln!("Lex error: {:?}", e);
            return 1;
        }
    };
    let token_spans: Vec<(lexer::Token, ast::Span)> = tokens
        .into_iter()
        .map(|(t, r)| {
            (
                t,
                ast::Span {
                    start: r.start,
                    end: r.end,
                },
            )
        })
        .collect();
    let (mut program, _) = parser::parse(token_spans);
    ast::resolve_aliases(&mut program);
    ast::desugar_dot_var_index(&mut program);
    program.source = Some(source);

    let pg = graph::build_graph(&program);

    // Parse flags.
    let mut fn_name: Option<String> = None;
    let mut reverse = false;
    let mut subgraph = false;
    let mut budget: Option<usize> = None;
    let mut dot = false;

    let mut i = 1;
    while i < args.len() {
        match args[i].as_str() {
            "--fn" => {
                if i + 1 >= args.len() {
                    eprintln!("error: --fn requires a function name");
                    return 1;
                }
                fn_name = Some(args[i + 1].clone());
                i += 2;
            }
            "--reverse" => {
                reverse = true;
                i += 1;
            }
            "--subgraph" => {
                subgraph = true;
                i += 1;
            }
            "--budget" => {
                if i + 1 >= args.len() {
                    eprintln!("error: --budget requires a number");
                    return 1;
                }
                match args[i + 1].parse::<usize>() {
                    Ok(v) => budget = Some(v),
                    Err(_) => {
                        eprintln!("error: --budget value must be a positive integer");
                        return 1;
                    }
                }
                i += 2;
            }
            "--dot" => {
                dot = true;
                i += 1;
            }
            _ => {
                eprintln!("unknown flag: {}", args[i]);
                return 1;
            }
        }
    }

    if dot {
        print!("{}", graph::to_dot(&pg));
        return 0;
    }

    if let Some(ref name) = fn_name {
        if reverse {
            match graph::query_reverse(&program, &pg, name) {
                Some(r) => match serde_json::to_string_pretty(&r) {
                    Ok(s) => println!("{}", s),
                    Err(e) => {
                        eprintln!("error serialising graph: {}", e);
                        return 1;
                    }
                },
                None => {
                    eprintln!("function '{}' not found", name);
                    return 1;
                }
            }
        } else if let Some(b) = budget {
            match graph::query_budget(&program, &pg, name, b) {
                Some(q) => match serde_json::to_string_pretty(&q) {
                    Ok(s) => println!("{}", s),
                    Err(e) => {
                        eprintln!("error serialising graph: {}", e);
                        return 1;
                    }
                },
                None => {
                    eprintln!("function '{}' not found", name);
                    return 1;
                }
            }
        } else if subgraph {
            match graph::query_subgraph(&program, &pg, name) {
                Some(q) => match serde_json::to_string_pretty(&q) {
                    Ok(s) => println!("{}", s),
                    Err(e) => {
                        eprintln!("error serialising graph: {}", e);
                        return 1;
                    }
                },
                None => {
                    eprintln!("function '{}' not found", name);
                    return 1;
                }
            }
        } else {
            match graph::query_fn(&program, &pg, name) {
                Some(q) => match serde_json::to_string_pretty(&q) {
                    Ok(s) => println!("{}", s),
                    Err(e) => {
                        eprintln!("error serialising graph: {}", e);
                        return 1;
                    }
                },
                None => {
                    eprintln!("function '{}' not found", name);
                    return 1;
                }
            }
        }
    } else {
        // Full graph output.
        match serde_json::to_string_pretty(&pg) {
            Ok(s) => println!("{}", s),
            Err(e) => {
                eprintln!("error serialising graph: {}", e);
                return 1;
            }
        }
    }
    0
}

/// Connect to MCP servers and return synthesized `Decl::Tool` nodes.
/// Returns `Err(message)` on failure.
#[cfg(feature = "tools")]
fn collect_mcp_tool_decls(path: Option<&str>) -> Result<Vec<ast::Decl>, String> {
    let path = match path {
        Some(p) => p,
        None => return Ok(vec![]),
    };
    let config = tools::mcp_provider::McpConfig::from_file(path).map_err(|e| e.to_string())?;
    let rt = tokio::runtime::Builder::new_current_thread()
        .enable_all()
        .build()
        .expect("tokio runtime");
    let provider = rt
        .block_on(tools::mcp_provider::McpProvider::connect(&config))
        .map_err(|e| format!("MCP error: {}", e))?;
    Ok(provider.tool_decls())
}

#[cfg(not(feature = "tools"))]
fn collect_mcp_tool_decls(path: Option<&str>) -> Result<Vec<ast::Decl>, String> {
    if path.is_some() {
        return Err("error: --mcp requires the 'tools' feature \
             (build with: cargo build --features tools)"
            .to_string());
    }
    Ok(vec![])
}

// ── `ilo serv` subcommand ──────────────────────────────────────────────────

/// Render a `Diagnostic` as a `serde_json::Value` for inclusion in serve responses.
fn diag_to_json(d: &Diagnostic) -> serde_json::Value {
    let s = diagnostic::json::render(d);
    serde_json::from_str(&s).unwrap_or(serde_json::json!({"message": s}))
}

/// Process a single serve request line and return the JSON response.
fn process_serv_request(
    line: &str,
    mcp_tool_decls: &[ast::Decl],
    #[cfg(feature = "tools")] provider: Option<std::sync::Arc<dyn tools::ToolProvider>>,
    #[cfg_attr(not(feature = "tools"), allow(unused_variables))] http_config: Option<
        &tools::http_provider::ToolsConfig,
    >,
    #[cfg(feature = "tools")] rt: std::sync::Arc<tokio::runtime::Runtime>,
) -> serde_json::Value {
    #[derive(serde::Deserialize)]
    struct Req {
        program: String,
        #[serde(default)]
        args: Vec<String>,
        func: Option<String>,
    }

    let req: Req = match serde_json::from_str(line) {
        Ok(r) => r,
        Err(e) => {
            return serde_json::json!({
                "error": {"phase": "request", "message": format!("invalid JSON: {e}")}
            });
        }
    };

    let start = std::time::Instant::now();
    let source = req.program.clone();

    // Lex
    let tokens = match lexer::lex(&source) {
        Ok(t) => t,
        Err(e) => {
            return serde_json::json!({
                "error": {
                    "phase": "lex",
                    "diagnostics": [diag_to_json(&Diagnostic::from(&e))]
                }
            });
        }
    };

    // Parse
    let token_spans: Vec<_> = tokens
        .into_iter()
        .map(|(t, r)| {
            (
                t,
                ast::Span {
                    start: r.start,
                    end: r.end,
                },
            )
        })
        .collect();
    let (mut program, parse_errors) = parser::parse(token_spans);
    ast::resolve_aliases(&mut program);
    ast::desugar_dot_var_index(&mut program);
    program.source = Some(source.clone());

    if !parse_errors.is_empty() {
        let diags: Vec<_> = parse_errors
            .iter()
            .map(|e| diag_to_json(&Diagnostic::from(e)))
            .collect();
        return serde_json::json!({"error": {"phase": "parse", "diagnostics": diags}});
    }

    // Inject static MCP tool decls so the verifier sees them
    if !mcp_tool_decls.is_empty() {
        let mut decls = mcp_tool_decls.to_vec();
        decls.append(&mut program.declarations);
        program.declarations = decls;
    }

    // Verify
    let vr = verify::verify(&program);
    if !vr.errors.is_empty() {
        let diags: Vec<_> = vr
            .errors
            .iter()
            .map(|e| diag_to_json(&Diagnostic::from(e).with_source(source.clone())))
            .collect();
        return serde_json::json!({"error": {"phase": "verify", "diagnostics": diags}});
    }

    // Run
    let func_name = req.func.as_deref();
    let run_args = parse_cli_args_typed(&program, func_name, &req.args);

    #[cfg(feature = "tools")]
    let result = if let Some(p) = provider {
        interpreter::run_with_tools(&program, func_name, run_args, p, rt)
    } else if let Some(cfg) = http_config {
        let p = std::sync::Arc::new(tools::http_provider::HttpProvider::new(cfg.clone()));
        interpreter::run_with_tools(&program, func_name, run_args, p, rt)
    } else {
        interpreter::run(&program, func_name, run_args)
    };

    #[cfg(not(feature = "tools"))]
    let result = interpreter::run(&program, func_name, run_args);

    let ms = start.elapsed().as_millis() as u64;

    match result {
        Ok(value) => match value {
            interpreter::Value::Ok(inner) => {
                let v = inner.to_json().unwrap_or(serde_json::Value::Null);
                serde_json::json!({"ok": v, "ms": ms})
            }
            interpreter::Value::Err(inner) => {
                let v = inner
                    .to_json()
                    .unwrap_or_else(|_| serde_json::Value::String(inner.to_string()));
                serde_json::json!({"error": {"phase": "program", "value": v}, "ms": ms})
            }
            other => {
                let v = other
                    .to_json()
                    .unwrap_or_else(|_| serde_json::Value::String(other.to_string()));
                serde_json::json!({"ok": v, "ms": ms})
            }
        },
        Err(e) => {
            let d = Diagnostic::from(&e).with_source(source);
            serde_json::json!({"error": {"phase": "runtime", "diagnostics": [diag_to_json(&d)]}})
        }
    }
}

fn type_to_ilo(ty: &ast::Type) -> String {
    match ty {
        ast::Type::Number => "n".to_string(),
        ast::Type::Text => "t".to_string(),
        ast::Type::Bool => "b".to_string(),
        ast::Type::Any => "_".to_string(),
        ast::Type::Optional(inner) => format!("O {}", type_to_ilo(inner)),
        ast::Type::List(inner) => format!("L {}", type_to_ilo(inner)),
        ast::Type::Map(k, v) => format!("M {} {}", type_to_ilo(k), type_to_ilo(v)),
        ast::Type::Result(ok, err) => format!("R {} {}", type_to_ilo(ok), type_to_ilo(err)),
        ast::Type::Sum(variants) => format!("S {}", variants.join(" ")),
        ast::Type::Fn(params, ret) => {
            let ps: Vec<_> = params.iter().map(type_to_ilo).collect();
            format!("F {} {}", ps.join(" "), type_to_ilo(ret))
        }
        ast::Type::Named(name) => name.clone(),
    }
}

/// Count brace depth: returns >0 if there are unclosed `{` braces.
/// Ignores braces inside string literals and comments.
fn brace_depth(s: &str) -> i32 {
    let mut depth: i32 = 0;
    let mut in_string = false;
    let mut prev_backslash = false;
    let mut chars = s.chars().peekable();
    while let Some(c) = chars.next() {
        if c == '-' && chars.peek() == Some(&'-') && !in_string {
            break; // `--` comment runs to end of input
        }
        if c == '"' {
            if in_string && prev_backslash {
                // Escaped quote inside string — don't toggle
                prev_backslash = false;
                continue;
            }
            in_string = !in_string;
            prev_backslash = false;
            continue;
        }
        if in_string {
            // Track backslashes: `\\` cancels out, so only odd runs count
            prev_backslash = c == '\\' && !prev_backslash;
            continue;
        }
        prev_backslash = false;
        if c == '{' {
            depth += 1;
        } else if c == '}' {
            depth -= 1;
        }
    }
    depth
}

/// Interactive REPL — define functions, evaluate expressions, accumulate state.
fn repl_cmd() {
    use std::io::{BufRead, Write};

    let version = env!("CARGO_PKG_VERSION");
    let renderer = AnsiRenderer { use_color: true };
    println!("ilo {version} — type :help for commands, :q to quit\n");

    // Accumulated function definitions across the session
    let mut defs: Vec<String> = Vec::new();

    let stdin = std::io::stdin();
    let mut reader = stdin.lock();

    loop {
        print!("> ");
        std::io::stdout().flush().ok();

        let mut line = String::new();
        match reader.read_line(&mut line) {
            Ok(0) => break, // Ctrl+D / EOF
            Ok(_) => {}
            Err(_) => break,
        }

        let mut input_buf = line.trim().to_string();
        if input_buf.is_empty() {
            continue;
        }

        // Multi-line: keep reading if braces are unbalanced or line ends with `;`
        while brace_depth(&input_buf) > 0 || input_buf.ends_with(';') {
            print!(".. ");
            std::io::stdout().flush().ok();
            let mut cont = String::new();
            match reader.read_line(&mut cont) {
                Ok(0) => break, // Ctrl+D
                Ok(_) => {}
                Err(_) => break,
            }
            let trimmed = cont.trim();
            if trimmed.is_empty() {
                break; // blank line submits what we have
            }
            // Join with `;` so multi-line fields/statements parse correctly,
            // but not when: buffer already ends with `;`, after `{`, or before `}`
            if !input_buf.ends_with('{') && !input_buf.ends_with(';') && !trimmed.starts_with('}') {
                input_buf.push(';');
            }
            input_buf.push_str(trimmed);
        }

        let input = input_buf.trim();
        if input.is_empty() {
            continue;
        }

        // Meta-commands (nvim-style)
        if input.starts_with(':') {
            match input {
                ":q" | ":q!" | ":x" | ":quit" | ":exit" => break,
                ":wq" => {
                    if defs.is_empty() {
                        eprintln!("no definitions to save");
                    } else {
                        eprintln!("usage: :w <file.ilo>");
                    }
                    continue;
                }
                _ if input.starts_with(":wq ") || input.starts_with(":w ") => {
                    let is_wq = input.starts_with(":wq");
                    let path = match input.split_once(' ') {
                        Some((_, p)) => p.trim(),
                        None => {
                            eprintln!("usage: :w <file.ilo>");
                            continue;
                        }
                    };
                    if defs.is_empty() {
                        eprintln!("no definitions to save");
                    } else if let Err(e) = std::fs::write(path, defs.join(" ") + "\n") {
                        eprintln!("error: {e}");
                    } else {
                        println!("saved {} definition(s) to {path}", defs.len());
                    }
                    if is_wq {
                        break;
                    } else {
                        continue;
                    }
                }
                ":defs" => {
                    if defs.is_empty() {
                        println!("(no definitions)");
                    } else {
                        for d in &defs {
                            println!("  {d}");
                        }
                    }
                    continue;
                }
                ":clear" => {
                    defs.clear();
                    println!("cleared all definitions");
                    continue;
                }
                ":help" => {
                    println!(":q :q! :x :quit :exit   quit");
                    println!(":w <file>               save definitions to file");
                    println!(":wq <file>              save and quit");
                    println!(":defs                   list defined functions");
                    println!(":clear                  clear all definitions");
                    println!(":help                   show this help");
                    continue;
                }
                _ => {
                    eprintln!("unknown command: {input}  (type :help)");
                    continue;
                }
            }
        }

        // Also support bare "exit"
        if input == "exit" || input == "quit" {
            break;
        }

        // Try to parse input as function definition(s) first
        let def_program = {
            let tokens = lexer::lex(input);
            if let Ok(tokens) = tokens {
                let token_spans: Vec<_> = tokens
                    .into_iter()
                    .map(|(t, r)| {
                        (
                            t,
                            ast::Span {
                                start: r.start,
                                end: r.end,
                            },
                        )
                    })
                    .collect();
                let (program, errors) = parser::parse(token_spans);
                if errors.is_empty()
                    && !program.declarations.is_empty()
                    && program.declarations.iter().all(|d| {
                        matches!(
                            d,
                            ast::Decl::Function { .. }
                                | ast::Decl::TypeDef { .. }
                                | ast::Decl::Alias { .. }
                        )
                    })
                {
                    Some(program)
                } else {
                    None
                }
            } else {
                None
            }
        };

        if let Some(program) = def_program {
            defs.push(input.to_string());

            for d in &program.declarations {
                match d {
                    ast::Decl::Function {
                        name,
                        params,
                        return_type,
                        ..
                    } => {
                        let params_str: Vec<_> = params
                            .iter()
                            .map(|p| format!("{}:{}", p.name, type_to_ilo(&p.ty)))
                            .collect();
                        println!(
                            "defined: {}({}) -> {}",
                            name,
                            params_str.join(", "),
                            type_to_ilo(return_type)
                        );
                    }
                    ast::Decl::TypeDef { name, fields, .. } => {
                        let fields_str: Vec<_> = fields
                            .iter()
                            .map(|f| format!("{}:{}", f.name, type_to_ilo(&f.ty)))
                            .collect();
                        println!("defined type: {}{{{}}}", name, fields_str.join(";"));
                    }
                    ast::Decl::Alias { name, target, .. } => {
                        println!("defined alias: {} = {}", name, type_to_ilo(target));
                    }
                    _ => {}
                }
            }
            continue;
        }

        // Expression or function call — wrap in a repl function with all accumulated defs
        // Use `repleval` as name (starts with letter, won't collide)
        let full_source = if defs.is_empty() {
            format!("repleval>n;{input}")
        } else {
            format!("{} repleval>n;{input}", defs.join(" "))
        };

        let tokens = match lexer::lex(&full_source) {
            Ok(t) => t,
            Err(e) => {
                let d = Diagnostic::from(&e);
                eprintln!("{}", renderer.render(&d));
                continue;
            }
        };

        let token_spans: Vec<_> = tokens
            .into_iter()
            .map(|(t, r)| {
                (
                    t,
                    ast::Span {
                        start: r.start,
                        end: r.end,
                    },
                )
            })
            .collect();
        let (mut full_program, parse_errors) = parser::parse(token_spans);
        ast::resolve_aliases(&mut full_program);
        ast::desugar_dot_var_index(&mut full_program);
        full_program.source = Some(full_source.clone());

        if !parse_errors.is_empty() {
            // Show errors relative to user input, not the wrapper
            for e in &parse_errors {
                let d = Diagnostic::from(e);
                eprintln!("{}", renderer.render(&d));
            }
            continue;
        }

        // Skip type checking for the repl wrapper — just run it
        // This allows expressions of any type to be evaluated
        match interpreter::run(&full_program, Some("repleval"), vec![]) {
            Ok(value) => println!("{value}"),
            Err(e) => {
                let d = Diagnostic::from(&e).with_source(full_source);
                eprintln!("{}", renderer.render(&d));
            }
        }
    }
}

/// AOT compile an ilo program to a standalone native binary.  Returns exit code.
#[cfg(feature = "cranelift")]
fn compile_cmd(args: &[String]) -> i32 {
    if args.is_empty() {
        eprintln!("Usage: ilo compile <file-or-code> [-o output] [func]");
        return 1;
    }

    let mut output_path: Option<String> = None;
    let mut source_arg: Option<&str> = None;
    let mut func_name: Option<&str> = None;
    let mut bench_mode = false;
    let mut i = 0;
    while i < args.len() {
        match args[i].as_str() {
            "-o" => {
                i += 1;
                if i >= args.len() {
                    eprintln!("Error: -o requires a path argument");
                    return 1;
                }
                output_path = Some(args[i].clone());
            }
            "--bench" => {
                bench_mode = true;
            }
            _ if source_arg.is_none() => {
                source_arg = Some(&args[i]);
            }
            _ => {
                func_name = Some(&args[i]);
            }
        }
        i += 1;
    }

    let source_arg = match source_arg {
        Some(s) => s,
        None => {
            eprintln!("Error: no source file or code provided");
            return 1;
        }
    };

    // Read source from file or treat as inline code
    let source = if std::path::Path::new(source_arg).is_file() {
        match std::fs::read_to_string(source_arg) {
            Ok(s) => s,
            Err(e) => {
                eprintln!("Error reading {}: {}", source_arg, e);
                return 1;
            }
        }
    } else {
        source_arg.to_string()
    };

    // Default output path: strip .ilo extension or use "a.out"
    let output = output_path.unwrap_or_else(|| {
        if source_arg.ends_with(".ilo") {
            source_arg.trim_end_matches(".ilo").to_string()
        } else {
            "a.out".to_string()
        }
    });

    // Lex
    let tokens = match lexer::lex(&source) {
        Ok(t) => t,
        Err(e) => {
            eprint!(
                "{}",
                AnsiRenderer { use_color: true }
                    .render(&Diagnostic::from(&e).with_source(source.clone()),)
            );
            return 1;
        }
    };
    let token_spans: Vec<(lexer::Token, ast::Span)> = tokens
        .into_iter()
        .map(|(t, r)| {
            (
                t,
                ast::Span {
                    start: r.start,
                    end: r.end,
                },
            )
        })
        .collect();

    // Parse
    let (mut program, parse_errors) = parser::parse(token_spans);
    if !parse_errors.is_empty() {
        for e in &parse_errors {
            let d = Diagnostic::from(e).with_source(source.clone());
            eprint!("{}", AnsiRenderer { use_color: true }.render(&d));
        }
        return 1;
    }
    ast::desugar_dot_var_index(&mut program);

    // Resolve imports
    let base_dir: Option<std::path::PathBuf> = if std::path::Path::new(source_arg).is_file() {
        std::path::Path::new(source_arg)
            .canonicalize()
            .ok()
            .and_then(|p| p.parent().map(|p| p.to_path_buf()))
    } else {
        None
    };
    let mut visited = std::collections::HashSet::new();
    let mut import_diagnostics: Vec<Diagnostic> = Vec::new();
    program.declarations = resolve_imports(
        program.declarations,
        base_dir.as_deref(),
        &mut visited,
        &mut import_diagnostics,
    );
    if !import_diagnostics.is_empty() {
        for d in &import_diagnostics {
            eprint!("{}", AnsiRenderer { use_color: true }.render(d));
        }
        return 1;
    }

    // Verify
    let verify_result = verify::verify(&program);
    for w in &verify_result.warnings {
        eprint!(
            "{}",
            AnsiRenderer { use_color: true }
                .render(&Diagnostic::from(w).with_source(source.clone()),)
        );
    }
    if !verify_result.errors.is_empty() {
        for e in &verify_result.errors {
            eprint!(
                "{}",
                AnsiRenderer { use_color: true }
                    .render(&Diagnostic::from(e).with_source(source.clone()),)
            );
        }
        return 1;
    }

    // Compile to bytecode
    let compiled = match vm::compile(&program) {
        Ok(c) => c,
        Err(e) => {
            eprintln!("Compile error: {}", e);
            return 1;
        }
    };

    // Determine entry function
    let entry = func_name.unwrap_or_else(|| {
        compiled
            .func_names
            .first()
            .map(|s| s.as_str())
            .unwrap_or("main")
    });

    // AOT compile
    let result = if bench_mode {
        vm::compile_cranelift::compile_to_bench_binary(&compiled, entry, &output)
    } else {
        vm::compile_cranelift::compile_to_binary(&compiled, entry, &output)
    };
    match result {
        Ok(()) => {
            eprintln!("Compiled: {}", output);
            0
        }
        Err(e) => {
            eprintln!("AOT compile error: {}", e);
            1
        }
    }
}

#[cfg(not(feature = "cranelift"))]
fn compile_cmd(_args: &[String]) -> i32 {
    eprintln!("Error: AOT compilation requires the cranelift feature (--features cranelift)");
    1
}

/// Stdio-based agent serve loop.
/// Reads one JSON request per line from stdin, writes one JSON response per line to stdout.
fn serv_cmd(args_slice: &[String]) {
    let mut mcp_path: Option<String> = None;
    let mut http_path: Option<String> = None;

    let mut i = 0;
    while i < args_slice.len() {
        match args_slice[i].as_str() {
            "--mcp" | "-m" => {
                if i + 1 >= args_slice.len() {
                    eprintln!("error: --mcp requires a path");
                    std::process::exit(1);
                }
                mcp_path = Some(args_slice[i + 1].clone());
                i += 2;
            }
            "--tools" | "-t" => {
                if i + 1 >= args_slice.len() {
                    eprintln!("error: --tools requires a path");
                    std::process::exit(1);
                }
                http_path = Some(args_slice[i + 1].clone());
                i += 2;
            }
            "-j" | "--json" => {
                // JSON protocol is always on in repl/serv; flag is a no-op (accepted for alias compat)
                i += 1;
            }
            _ => {
                eprintln!("unknown flag: {}", args_slice[i]);
                eprintln!("Usage: ilo repl [-j] [--mcp <path>] [--tools <path>]");
                std::process::exit(1);
            }
        }
    }

    // Load HTTP config (sync)
    let http_config: Option<tools::http_provider::ToolsConfig> = http_path.as_ref().map(|p| {
        tools::http_provider::ToolsConfig::from_file(p).unwrap_or_else(|e| {
            eprintln!("{}", e);
            std::process::exit(1);
        })
    });

    // Create tokio runtime once (used for MCP connect + all tool calls)
    #[cfg(feature = "tools")]
    let rt = std::sync::Arc::new(
        tokio::runtime::Builder::new_current_thread()
            .enable_all()
            .build()
            .expect("tokio runtime"),
    );

    // Connect to MCP once, keep provider + static decls alive for all requests
    #[cfg(feature = "tools")]
    let (mcp_tool_decls, mcp_provider_arc): (
        Vec<ast::Decl>,
        Option<std::sync::Arc<dyn tools::ToolProvider>>,
    ) = if let Some(ref path) = mcp_path {
        let config = tools::mcp_provider::McpConfig::from_file(path).unwrap_or_else(|e| {
            eprintln!("{}", e);
            std::process::exit(1);
        });
        let provider = rt
            .block_on(tools::mcp_provider::McpProvider::connect(&config))
            .unwrap_or_else(|e| {
                eprintln!("MCP error: {}", e);
                std::process::exit(1);
            });
        let decls = provider.tool_decls();
        (decls, Some(std::sync::Arc::new(provider)))
    } else {
        (vec![], None)
    };

    #[cfg(not(feature = "tools"))]
    let mcp_tool_decls: Vec<ast::Decl> = {
        if mcp_path.is_some() {
            eprintln!(
                "error: --mcp requires the 'tools' feature \
                 (build with: cargo build --features tools)"
            );
            std::process::exit(1);
        }
        vec![]
    };

    // Signal ready
    println!("{}", serde_json::json!({"ready": true}));

    use std::io::BufRead;
    let stdin = std::io::stdin();
    for line in stdin.lock().lines() {
        let line = match line {
            Ok(l) => l,
            Err(e) => {
                eprintln!("stdin read error: {}", e);
                break;
            }
        };
        if line.trim().is_empty() {
            continue;
        }

        let resp = process_serv_request(
            &line,
            &mcp_tool_decls,
            #[cfg(feature = "tools")]
            mcp_provider_arc.as_ref().map(std::sync::Arc::clone),
            http_config.as_ref(),
            #[cfg(feature = "tools")]
            std::sync::Arc::clone(&rt),
        );
        println!("{}", resp);
    }
}

/// Scan args for `--run-tree` / `--run` / `--run-vm` / `--run-cranelift` /
/// `--run-llvm` anywhere in the list and remove them. argv[0] (binary name)
/// is preserved at position 0. Returns the chosen engine (if any) plus the
/// remaining args. Multiple conflicting engine flags produce an error.
fn extract_run_engine_flag(
    args: Vec<String>,
) -> Result<(Option<cli::Engine>, Vec<String>), String> {
    let mut engine: Option<cli::Engine> = None;
    let mut conflict = false;
    let mut remaining = Vec::with_capacity(args.len());

    for arg in args {
        let candidate = match arg.as_str() {
            "--run-cranelift" => Some(cli::Engine::Cranelift),
            "--run-llvm" => Some(cli::Engine::Llvm),
            "--run-vm" => Some(cli::Engine::Vm),
            "--run" | "--run-tree" => Some(cli::Engine::Tree),
            _ => None,
        };
        match candidate {
            Some(e) => match engine {
                None => engine = Some(e),
                Some(prev) if prev == e => {} // identical flag repeated: ignore
                Some(_) => conflict = true,
            },
            None => remaining.push(arg),
        }
    }

    if conflict {
        return Err(
            "error: --run, --run-tree, --run-vm, --run-cranelift, --run-llvm are mutually exclusive"
                .to_string(),
        );
    }

    Ok((engine, remaining))
}

/// Scan args for --json/-j, --text/-t, --ansi/-a, --no-hints/-nh.
/// Return (mode, explicit_json, no_hints, remaining_args).
/// Multiple format flags -> error + exit(1).
/// `explicit_json` is true only when the user passed --json/-j; auto-detection never sets it.
fn detect_output_mode(args: Vec<String>) -> (OutputMode, bool, bool, Vec<String>) {
    let mut mode: Option<OutputMode> = None;
    let mut remaining = Vec::with_capacity(args.len());
    let mut conflict = false;
    let mut no_hints = false;

    for arg in args {
        match arg.as_str() {
            "--json" | "-j" => {
                if mode.is_some() {
                    conflict = true;
                } else {
                    mode = Some(OutputMode::Json);
                }
            }
            "--text" | "-t" => {
                if mode.is_some() {
                    conflict = true;
                } else {
                    mode = Some(OutputMode::Text);
                }
            }
            "--ansi" | "-a" => {
                if mode.is_some() {
                    conflict = true;
                } else {
                    mode = Some(OutputMode::Ansi);
                }
            }
            "--no-hints" | "-nh" => {
                no_hints = true;
            }
            _ => remaining.push(arg),
        }
    }

    if conflict {
        eprintln!("error: --json, --text, and --ansi are mutually exclusive");
        std::process::exit(1);
    }

    let explicit_json = matches!(mode, Some(OutputMode::Json));

    let resolved = mode.unwrap_or_else(|| {
        // Auto-detect: isatty(stderr) && !NO_COLOR → Ansi; isatty && NO_COLOR → Text; !isatty → Json
        use std::io::IsTerminal;
        let is_tty = std::io::stderr().is_terminal();
        let no_color = std::env::var("NO_COLOR").is_ok();
        if is_tty && !no_color {
            OutputMode::Ansi
        } else if is_tty {
            OutputMode::Text
        } else {
            OutputMode::Json
        }
    });

    (resolved, explicit_json, no_hints, remaining)
}

/// Replace the contents of string literals with spaces, preserving length.
/// `"https://x.com"` → `"               "`. This prevents cross-language pattern
/// detection from matching inside strings (e.g. `//` in URLs).
fn strip_string_contents(source: &str) -> String {
    let mut result = String::with_capacity(source.len());
    let mut in_string = false;
    let mut chars = source.chars().peekable();
    while let Some(c) = chars.next() {
        if in_string {
            if c == '\\' {
                // Escaped character — skip both backslash and next char
                result.push(' ');
                if chars.next().is_some() {
                    result.push(' ');
                }
            } else if c == '"' {
                result.push('"');
                in_string = false;
            } else {
                result.push(' ');
            }
        } else if c == '"' {
            result.push('"');
            in_string = true;
        } else {
            result.push(c);
        }
    }
    result
}

/// Collect idiomatic hints by scanning source text for non-canonical forms.
/// Returns a list of human-readable hint strings.
///
/// Word-boundary scans (alias hints) run over real lexer tokens, not raw text:
/// re-lexing skips comments, strings, numbers, operators, and CLI argv, so a
/// `tail` substring inside a comment line, a string literal, or a file path
/// printed to stderr won't fire `hint: \`tail\` → \`tl\``. The text-based `==`
/// scan strips both strings and comments first for the same reason.
#[cfg(test)]
fn collect_hints(source: &str) -> Vec<String> {
    collect_hints_with_program(source, None)
}

fn collect_hints_with_program(source: &str, program: Option<&ast::Program>) -> Vec<String> {
    let mut hints = Vec::new();
    // Hint: == → = saves 1 character
    // Scan for `==` outside string literals and comments. We don't use the
    // lexer here because logos collapses both `=` and `==` into `Token::Eq`,
    // so the distinction is only visible in raw text.
    let stripped = strip_string_and_comment_contents(source);
    let mut pos = 0;
    let bytes = stripped.as_bytes();
    while pos + 1 < bytes.len() {
        if bytes[pos] == b'=' && bytes[pos + 1] == b'=' {
            hints.push("hint: `==` → `=` saves 1 char (both mean equality in ilo)".to_string());
            break; // one hint per pattern type is enough
        }
        pos += 1;
    }
    // Hint: long-form builtin aliases → canonical short form.
    // Use lexer tokens so we only consider real source identifiers — not words
    // appearing in comments, string literals, or anything outside the source
    // itself. Falling back to no hint on lex failure is fine: the run already
    // succeeded if we got here, so a re-lex failure is implausible, but we
    // err on the side of "no hint" rather than spurious noise.
    if let Ok(tokens) = lexer::lex(source) {
        for (tok, _) in &tokens {
            if let lexer::Token::Ident(word) = tok
                && let Some(short) = ast::resolve_alias(word)
            {
                hints.push(format!("hint: `{word}` → `{short}` (canonical short form)"));
                break; // one hint per run is enough
            }
        }
        // Hint: same-precedence prefix-arithmetic-op pairs trip the
        // left-to-right intuition. `*/a b c` parses as `*(/a b) c == (a/b)*c`
        // because the first prefix op binds the nested prefix subexpression as
        // its LEFT operand. Personas reading `* / a b c` left-to-right expect
        // `(a*b)/c` and silently get the wrong answer. Fire on the four mixed
        // same-precedence pairs (`*/`, `/*`, `+-`, `-+`) when both tokens are
        // in prefix position (previous token is not a value-yielding atom).
        // Same-op repeats like `++a b c == (a+b)+c` already match left-to-right
        // intuition and are skipped.
        if let Some(hint) = detect_prefix_precedence_trap(&tokens) {
            hints.push(hint);
        }
    }
    // AST-aware hint: braced-conditional guard `cond{^"err"}` discards the
    // body value, which is almost always not what the author intended.
    // Personas (qa-tester, scientific-researcher rerun3) reach for this
    // shape expecting early-return semantics. The braceless guard form
    // `<k 1 ^"err"` or explicit `ret`/`!`-propagate covers the real intent.
    if let Some(prog) = program {
        for decl in &prog.declarations {
            if let ast::Decl::Function { body, .. } = decl
                && walk_for_discarded_guard_result(body)
            {
                hints.push(
                    "hint: `cond{^\"err\"}` and `cond{~v}` discard the body expression. For early-return use the braceless form `cond ^\"err\"` or wrap the body in `{ret ^\"err\"}`."
                        .to_string(),
                );
                break; // one hint per run is enough
            }
        }
    }
    hints
}

/// Detect same-precedence prefix-arithmetic-op pairs that parse in a way
/// that contradicts the human left-to-right reading. Returns `Some(hint)` for
/// the first such occurrence, or `None`.
///
/// Pattern: `<op1> <op2>` adjacent at a prefix position, where:
///   * `(op1, op2)` is one of `(*, /)`, `(/, *)`, `(+, -)`, `(-, +)`
///   * The token before `op1` is start-of-input or a non-value-yielding
///     token (so `op1` is genuinely in prefix position, not infix).
///   * `op2` is followed by at least one value-yielding token (otherwise
///     it isn't a prefix op either).
///
/// We rely on the lexer's greedy-negative-literal rule (`-5` lexes as
/// `Number(-5)`, not `Minus, Number(5)`), so `*-5 b c` will NOT match this
/// pattern — the negative literal absorbs the minus. Spelt-out `*- 5 b c`
/// (with a space) does lex as `Star, Minus, Number, Ident`, and is a true
/// prefix-pair: fire.
///
/// Suppression: when the immediate predecessor of `op1` is `LParen`, the
/// author has explicitly grouped the prefix expression. The parenthesised
/// form is the recommended shape (the hint itself suggests grouping as the
/// canonical disambiguation), so flagging it would be self-contradictory.
/// Nested parens are covered too because the immediate predecessor of `op1`
/// is still `LParen` in `((/ *a b c))`.
fn detect_prefix_precedence_trap(
    tokens: &[(lexer::Token, std::ops::Range<usize>)],
) -> Option<String> {
    use lexer::Token::*;
    for i in 0..tokens.len().saturating_sub(1) {
        let op1 = &tokens[i].0;
        let op2 = &tokens[i + 1].0;
        // (shape, parsed_as, swap_form, bind_form). `bind_form` shows the
        // explicit two-statement rewrite that yields the OTHER grouping, so
        // the persona has both a concrete swap example and a concrete bind
        // example to copy.
        let pair = match (op1, op2) {
            (Star, Slash) => Some(("*/", "(a/b)*c", "/*a b c", "r=*a b;/r c")),
            (Slash, Star) => Some(("/*", "(a*b)/c", "*/a b c", "r=/a b;*r c")),
            (Plus, Minus) => Some(("+-", "(a-b)+c", "-+a b c", "r=+a b;- r c")),
            (Minus, Plus) => Some(("-+", "(a+b)-c", "+-a b c", "r=-a b;+r c")),
            _ => None,
        };
        let Some((shape, parsed_as, swap_form, bind_form)) = pair else {
            continue;
        };
        // Prefix-position check: the previous token must not be value-yielding.
        if i > 0 && is_value_yielding(&tokens[i - 1].0) {
            continue;
        }
        // Parenthesised-form suppression: if op1 sits directly after `(`, the
        // author has explicitly grouped the prefix expression. That IS the
        // recommended shape, so don't nag. Covers nested parens too because
        // the immediate predecessor is still `LParen`.
        if i > 0 && matches!(&tokens[i - 1].0, LParen) {
            continue;
        }
        // The pair must be followed by at least one value-yielding token to
        // function as prefix ops. Otherwise it isn't a prefix pair at all.
        if i + 2 >= tokens.len() || !is_value_yielding(&tokens[i + 2].0) {
            continue;
        }
        return Some(format!(
            "hint: `{shape}a b c` parses as `{parsed_as}` (inner prefix op binds first). \
             For the other order, swap the ops (`{swap_form}`) or bind: `{bind_form}`",
        ));
    }
    None
}

/// Tokens that yield a value, used to distinguish prefix position from infix.
/// If the token immediately before an operator yields a value, the operator
/// is being used in infix form (e.g. `x * y`), not prefix.
fn is_value_yielding(tok: &lexer::Token) -> bool {
    use lexer::Token::*;
    matches!(
        tok,
        Ident(_)
            | Number(_)
            | Text(_)
            | True
            | False
            | Nil
            | RParen
            | RBracket
            | RBrace
            | Bang
            | BangBang
    )
}

/// Walk a body looking for a braced-conditional guard whose final body
/// statement is an `Expr::Err(_)` or `Expr::Ok(_)` expression — a strong
/// signal the author meant `ret ^...` / `ret ~...` but wrote `cond{^...}`,
/// which silently discards the value.
fn walk_for_discarded_guard_result(body: &[ast::Spanned<ast::Stmt>]) -> bool {
    for s in body {
        if walk_stmt_for_discarded_guard_result(&s.node) {
            return true;
        }
    }
    false
}

fn walk_stmt_for_discarded_guard_result(stmt: &ast::Stmt) -> bool {
    match stmt {
        ast::Stmt::Guard {
            body,
            else_body,
            braceless,
            ..
        } => {
            // Only fire on the original target shape: a single-statement
            // braced body whose sole expression is `^...` or `~...`. The
            // single-statement requirement matters because multi-statement
            // bodies like `{prnt "..."; ~"ok"}` legitimately use the trailing
            // `~v` as the body's return value, the author knows the value
            // is the guard's result, not a discarded early-return. Firing
            // there is a false positive that erodes trust in the hint.
            if !*braceless
                && body.len() == 1
                && let Some(only) = body.first()
                && matches!(
                    only.node,
                    ast::Stmt::Expr(ast::Expr::Err(_) | ast::Expr::Ok(_))
                )
            {
                return true;
            }
            if walk_for_discarded_guard_result(body) {
                return true;
            }
            if let Some(eb) = else_body
                && walk_for_discarded_guard_result(eb)
            {
                return true;
            }
            false
        }
        ast::Stmt::Match { arms, .. } => arms
            .iter()
            .any(|a| walk_for_discarded_guard_result(&a.body)),
        ast::Stmt::ForEach { body, .. }
        | ast::Stmt::ForRange { body, .. }
        | ast::Stmt::While { body, .. } => walk_for_discarded_guard_result(body),
        _ => false,
    }
}

/// Strip both string-literal contents and `--`-prefixed line comments,
/// replacing their contents with spaces so byte offsets are preserved.
/// Used by the text-based `==` scan so a literal `==` inside a string or
/// comment doesn't trigger the hint.
fn strip_string_and_comment_contents(source: &str) -> String {
    let stripped = strip_string_contents(source);
    let mut out = String::with_capacity(stripped.len());
    let mut chars = stripped.chars().peekable();
    let mut in_comment = false;
    while let Some(c) = chars.next() {
        if in_comment {
            if c == '\n' {
                in_comment = false;
                out.push(c);
            } else {
                out.push(' ');
            }
        } else if c == '-' && chars.peek() == Some(&'-') {
            // Consume the second '-' and enter comment mode
            chars.next();
            out.push(' ');
            out.push(' ');
            in_comment = true;
        } else {
            out.push(c);
        }
    }
    out
}

/// Emit hints to the appropriate output channel.
/// TTY → stderr, JSON → adds to JSON output (caller handles), pipe → nothing.
fn emit_hints(hints: &[String], mode: OutputMode) {
    if hints.is_empty() {
        return;
    }
    match mode {
        OutputMode::Ansi | OutputMode::Text => {
            for hint in hints {
                eprintln!("{hint}");
            }
        }
        OutputMode::Json => {
            // JSON mode: hints go to stderr as JSON array
            let json = serde_json::json!({ "hints": hints });
            eprintln!("{}", json);
        }
    }
}

/// Scan source for common cross-language patterns and emit a single warning if found.
/// Non-fatal — program still attempts to run.
fn warn_cross_language_syntax(source: &str, mode: OutputMode) {
    let patterns: &[(&str, &str)] = &[
        ("&&", "'&&' — ilo uses '&' for AND"),
        ("||", "'||' — ilo uses '|' for OR"),
        ("->", "'->' — ilo uses '>' for return type separator"),
        ("//", "'//' — ilo uses '--' for comments"),
    ];

    // Strip string literal contents AND `--` comments so patterns inside
    // `"..."` or `--` lines don't trigger warnings. Avoids false positives
    // for URLs like `"https://example.com"` and for comments that mention
    // cross-language syntax illustratively (e.g. `-- not: a -> b`).
    let stripped = strip_string_and_comment_contents(source);

    let details: Vec<&str> = patterns
        .iter()
        .filter(|(pat, _)| stripped.contains(*pat))
        .map(|(_, desc)| *desc)
        .collect();

    if details.is_empty() {
        return;
    }

    let msg = format!(
        "source contains syntax from another language: {}",
        details.join(", ")
    );
    let d = Diagnostic::warning(msg);
    report_diagnostic(&d, mode);
}

/// Return the declared name of a `Decl`, if it has one.
fn decl_name(decl: &ast::Decl) -> Option<&str> {
    match decl {
        ast::Decl::Function { name, .. } => Some(name),
        ast::Decl::Tool { name, .. } => Some(name),
        ast::Decl::TypeDef { name, .. } => Some(name),
        ast::Decl::Alias { name, .. } => Some(name),
        ast::Decl::Use { .. } | ast::Decl::Error { .. } => None,
    }
}

/// Resolve all `Decl::Use` nodes in `decls` recursively, returning a flat
/// merged list with imported declarations prepended and `Use` nodes stripped.
///
/// - `base_dir`: directory of the importing file (used to resolve relative paths).
///   `None` means inline code — `use` is not supported without a file context.
/// - `visited`: canonical paths already in the import chain; circular imports are errors.
/// - `diagnostics`: errors are pushed here (file-not-found, circular, parse failures).
fn resolve_imports(
    decls: Vec<ast::Decl>,
    base_dir: Option<&std::path::Path>,
    visited: &mut std::collections::HashSet<std::path::PathBuf>,
    diagnostics: &mut Vec<Diagnostic>,
) -> Vec<ast::Decl> {
    let mut result: Vec<ast::Decl> = Vec::new();

    for decl in decls {
        if let ast::Decl::Use { path, only, span } = decl {
            let Some(dir) = base_dir else {
                diagnostics.push(
                    Diagnostic::error(
                        "`use` requires a file path context — not supported in inline code",
                    )
                    .with_code("ILO-P017")
                    .with_span(span, "here"),
                );
                continue;
            };

            let file_path = dir.join(&path);
            let canonical = match file_path.canonicalize() {
                Ok(c) => c,
                Err(_) => {
                    diagnostics.push(
                        Diagnostic::error(format!("use \"{}\": file not found", path))
                            .with_code("ILO-P017")
                            .with_span(span, "imported here"),
                    );
                    continue;
                }
            };

            if visited.contains(&canonical) {
                diagnostics.push(
                    Diagnostic::error(format!("use \"{}\": circular import", path))
                        .with_code("ILO-P018")
                        .with_span(span, "imported here"),
                );
                continue;
            }

            let source = match std::fs::read_to_string(&canonical) {
                Ok(s) => s,
                Err(e) => {
                    diagnostics.push(
                        Diagnostic::error(format!("use \"{}\": {}", path, e))
                            .with_code("ILO-P017")
                            .with_span(span, "imported here"),
                    );
                    continue;
                }
            };

            let tokens = match lexer::lex(&source) {
                Ok(t) => t,
                Err(e) => {
                    diagnostics.push(Diagnostic::from(&e));
                    continue;
                }
            };

            let token_spans: Vec<(lexer::Token, ast::Span)> = tokens
                .into_iter()
                .map(|(t, r)| {
                    (
                        t,
                        ast::Span {
                            start: r.start,
                            end: r.end,
                        },
                    )
                })
                .collect();

            let (mut imported_prog, parse_errors) = parser::parse(token_spans);
            ast::resolve_aliases(&mut imported_prog);
            ast::desugar_dot_var_index(&mut imported_prog);
            for e in &parse_errors {
                diagnostics.push(Diagnostic::from(e));
            }

            visited.insert(canonical.clone());
            let imported_dir = canonical.parent();
            let imported_decls = resolve_imports(
                imported_prog.declarations,
                imported_dir,
                visited,
                diagnostics,
            );
            visited.remove(&canonical);

            // Apply `only [...]` filter if specified
            let filtered = if let Some(ref names) = only {
                // Warn about any requested names that weren't found
                for name in names {
                    let found = imported_decls
                        .iter()
                        .any(|d| decl_name(d) == Some(name.as_str()));
                    if !found {
                        diagnostics.push(
                            Diagnostic::error(format!(
                                "use \"{}\": name '{}' not found in imported file",
                                path, name
                            ))
                            .with_code("ILO-P019")
                            .with_span(span, "imported here"),
                        );
                    }
                }
                imported_decls
                    .into_iter()
                    .filter(|d| {
                        decl_name(d)
                            .map(|n| names.iter().any(|s| s == n))
                            .unwrap_or(false)
                    })
                    .collect::<Vec<_>>()
            } else {
                imported_decls
            };

            // Prepend imported declarations (so they appear before the importer's own decls)
            result.extend(filtered);
        } else {
            result.push(decl);
        }
    }

    result
}

fn report_diagnostic(d: &Diagnostic, mode: OutputMode) {
    let s = match mode {
        OutputMode::Ansi => AnsiRenderer { use_color: true }.render(d),
        OutputMode::Text => AnsiRenderer { use_color: false }.render(d),
        // JSON mode: one object per line (NDJSON) so multiple errors are parseable.
        OutputMode::Json => format!("{}\n", json::render(d)),
    };
    eprint!("{}", s);
}

/// Load a single env file into the process environment.
/// Lines starting with `#` are comments. Blank lines are skipped.
/// Format: `KEY=VALUE` — no quoting, no variable expansion.
/// Does NOT overwrite variables already set in the environment.
fn load_env_file(path: &str) {
    let Ok(contents) = std::fs::read_to_string(path) else {
        return;
    };
    for line in contents.lines() {
        let line = line.trim();
        if line.is_empty() || line.starts_with('#') {
            continue;
        }
        if let Some((key, val)) = line.split_once('=') {
            let key = key.trim();
            let val = val.trim();
            if !key.is_empty() && std::env::var(key).is_err() {
                // SAFETY: single-threaded at startup, no concurrent env access
                unsafe { std::env::set_var(key, val) };
            }
        }
    }
}

/// Load `.env.local` then `.env` from the current working directory.
/// `.env.local` takes priority (loaded first; later files don't overwrite).
fn load_dotenv() {
    load_env_file(".env.local");
    load_env_file(".env");
}

fn main() {
    load_dotenv();

    let raw_args: Vec<String> = std::env::args().collect();

    // Special-case: `ilo -ai` (hidden alias for compact spec)
    if raw_args.get(1).map(|s| s.as_str()) == Some("-ai") {
        print!("{}", compact_spec());
        std::process::exit(0);
    }

    // Try clap parse.  When it fails (e.g. `ilo 'fn x:n>n;*x 2' 5` or
    // `ilo --help`), reconstruct a Cli with the raw positional args.
    let (cli, bare_args_have_bin_name) = match cli::Cli::try_parse_from(&raw_args) {
        Ok(c) => (c, false),
        Err(_) => {
            // Build a Cli whose `cmd` is None and `args` carries the raw argv
            // (including the binary name at position 0).
            (
                cli::Cli {
                    cmd: None,
                    global: cli::Global {
                        ansi: false,
                        text: false,
                        json: false,
                        no_hints: false,
                    },
                    args: raw_args,
                },
                true,
            )
        }
    };

    let code = dispatch_cli(cli, bare_args_have_bin_name);
    if code != 0 {
        std::process::exit(code);
    }
}

/// Top-level dispatch: returns the process exit code (0 = success).
/// `bare_has_bin` is true when the `None` arm's args already include argv[0] (binary name).
fn dispatch_cli(cli: cli::Cli, bare_has_bin: bool) -> i32 {
    match cli.cmd {
        Some(cli::Cmd::Tools(t)) => {
            let mut args: Vec<String> = Vec::new();
            if let Some(ref p) = t.mcp_path {
                args.push("--mcp".into());
                args.push(p.clone());
            }
            if let Some(ref p) = t.tools_path {
                args.push("--tools".into());
                args.push(p.clone());
            }
            if t.human {
                args.push("--human".into());
            }
            if t.ilo {
                args.push("--ilo".into());
            }
            if t.json {
                args.push("--json".into());
            }
            if t.full {
                args.push("--full".into());
            }
            if t.graph {
                args.push("--graph".into());
            }
            tools_cmd(&args)
        }
        Some(cli::Cmd::Graph(g)) => {
            let mut args: Vec<String> = vec![g.file];
            if let Some(ref n) = g.fn_name {
                args.push("--fn".into());
                args.push(n.clone());
            }
            if g.reverse {
                args.push("--reverse".into());
            }
            if g.subgraph {
                args.push("--subgraph".into());
            }
            if let Some(b) = g.budget {
                args.push("--budget".into());
                args.push(b.to_string());
            }
            if g.dot {
                args.push("--dot".into());
            }
            graph_cmd(&args)
        }
        Some(cli::Cmd::Repl) => {
            if cli.global.json {
                serv_cmd(&["-j".to_string()]);
            } else {
                repl_cmd();
            }
            0
        }
        Some(cli::Cmd::Serv(s)) => {
            let mut args: Vec<String> = vec!["-j".into()];
            if let Some(ref p) = s.mcp_path {
                args.push("--mcp".into());
                args.push(p.clone());
            }
            if let Some(ref p) = s.tools_path {
                args.push("--tools".into());
                args.push(p.clone());
            }
            serv_cmd(&args);
            0
        }
        Some(cli::Cmd::Compile(c)) => {
            let mut args: Vec<String> = vec![c.source];
            if let Some(ref o) = c.output {
                args.push("-o".into());
                args.push(o.clone());
            }
            if c.bench {
                args.push("--bench".into());
            }
            if let Some(ref f) = c.func {
                args.push(f.clone());
            }
            compile_cmd(&args)
        }
        Some(cli::Cmd::Explain(e)) => match diagnostic::registry::lookup(&e.code) {
            Some(entry) => {
                print!("{}", entry.long);
                0
            }
            None => {
                eprintln!("unknown error code: {}", e.code);
                eprintln!("Error codes have the form ILO-L001, ILO-P001, ILO-T001, ILO-R001.");
                1
            }
        },
        Some(cli::Cmd::Spec(s)) => {
            match s.topic.as_deref() {
                Some("lang") => print!("{}", include_str!("../SPEC.md")),
                Some("ai") => print!("{}", compact_spec()),
                _ => print_help(),
            }
            0
        }
        Some(cli::Cmd::Version) => {
            println!("ilo {}", env!("CARGO_PKG_VERSION"));
            0
        }
        Some(cli::Cmd::Run(r)) => {
            let mode = cli.global.output_mode();
            let explicit_json = cli.global.explicit_json();
            let no_hints = cli.global.no_hints;
            dispatch_run(r, mode, explicit_json, no_hints)
        }
        None => {
            // No subcommand — bare positional args (e.g. `ilo 'fn x:n>n;*x 2' 5`)
            // dispatch_bare_args expects args[0] = binary name.
            let args = if bare_has_bin {
                cli.args
            } else {
                let mut full = vec!["ilo".to_string()];
                full.extend(cli.args);
                full
            };
            dispatch_bare_args(args, &cli.global)
        }
    }
}

/// Handle bare positional args (no subcommand).
///
/// Covers: `ilo <code> [func] [args]`, `ilo <file.ilo> [func] [args]`,
/// `ilo --version`, `ilo --help`, `ilo -e <code>`, `ilo --explain <code>`,
/// and all `--run-*` / `--emit` / `--bench` / `--dense` / `--expanded` flags.
fn dispatch_bare_args(raw_args: Vec<String>, global: &cli::Global) -> i32 {
    // Strip output mode flags from raw_args (--json/-j, --text/-t, --ansi/-a, --no-hints/-n)
    let (mode, explicit_json, no_hints, args) = detect_output_mode(raw_args);

    // Extract --run-* engine flags from anywhere in the arg list so users can
    // pass them before or after positional args. Examples that should be
    // equivalent:
    //   ilo 'f>n;5' --run-tree f
    //   ilo 'f>n;5' f --run-tree
    //   ilo --run-tree 'f>n;5' f
    //   ilo file.ilo --run-tree main
    //   ilo --run-tree file.ilo main
    //
    // Conflicting flags (e.g. --run-tree --run-vm) still error cleanly.
    let (pre_engine, args) = match extract_run_engine_flag(args) {
        Ok(v) => v,
        Err(msg) => {
            eprintln!("{msg}");
            return 1;
        }
    };

    // Extract --ast flag from anywhere in the arg list so it can sit before
    // the source, after the source, or after positional args. The flag
    // forces the AST-dump path; without it `ilo file.ilo` auto-runs a
    // single-function file or prints a friendly function listing.
    let (pre_ast, args) = {
        let mut found = false;
        let mut filtered: Vec<String> = Vec::with_capacity(args.len());
        for a in args.into_iter() {
            if a == "--ast" {
                found = true;
            } else {
                filtered.push(a);
            }
        }
        (found, filtered)
    };

    // Override with clap-parsed global flags if they were set
    let mode = if global.ansi {
        OutputMode::Ansi
    } else if global.text {
        OutputMode::Text
    } else if global.json {
        OutputMode::Json
    } else {
        mode
    };
    let explicit_json = explicit_json || global.explicit_json();
    let no_hints = no_hints || global.no_hints;

    if args.len() < 2 {
        eprintln!(
            "Usage: ilo <file-or-code> [args... | --run func args... | --bench func args... | --emit python]"
        );
        eprintln!("       ilo repl                                  Interactive REPL");
        eprintln!("       ilo serv [--mcp <path>] [--tools <path>]  Stdio agent loop");
        eprintln!("       ilo graph <file> [--fn NAME] [--dot]      Dependency graph");
        eprintln!("       ilo compile <file> [-o out] [func]        AOT compile to binary");
        eprintln!("       ilo help | -h     Show usage and examples");
        eprintln!("       ilo help lang     Show language specification");
        eprintln!("       ilo help ai | -ai Compact spec for LLM consumption");
        eprintln!("       ilo --version | -V");
        return 1;
    }

    if args[1] == "--version" || args[1] == "-V" {
        println!("ilo {}", env!("CARGO_PKG_VERSION"));
        return 0;
    }

    if args[1] == "--explain" {
        return match args.get(2) {
            Some(code) => match diagnostic::registry::lookup(code) {
                Some(entry) => {
                    print!("{}", entry.long);
                    0
                }
                None => {
                    eprintln!("unknown error code: {code}");
                    eprintln!("Error codes have the form ILO-L001, ILO-P001, ILO-T001, ILO-R001.");
                    1
                }
            },
            None => {
                eprintln!("Usage: ilo --explain <code>  (e.g. ilo --explain ILO-T005)");
                1
            }
        };
    }

    if args[1] == "-ai" {
        print!("{}", compact_spec());
        return 0;
    }

    if args[1] == "help" || args[1] == "--help" || args[1] == "-h" {
        if args.len() > 2 && args[2] == "lang" {
            print!("{}", include_str!("../SPEC.md"));
        } else if args.len() > 2 && args[2] == "ai" {
            print!("{}", compact_spec());
        } else {
            print_help();
        }
        return 0;
    }

    // Determine source: file path, `-e <code>`, or inline code.
    // We pass the source *identifier* to RunArgs.source — dispatch_run handles
    // file-vs-inline detection and reading.
    let (source, mode_args_start) = if std::path::Path::new(&args[1]).is_file() {
        // Pass the file path through; dispatch_run will read it.
        (args[1].clone(), 2)
    } else if args[1] == "-e" {
        if args.len() < 3 || args[2].is_empty() {
            eprintln!("Usage: ilo <file-or-code> [args... | --run func args... | --emit python]");
            return 1;
        }
        (args[2].clone(), 3)
    } else {
        if args[1].is_empty() {
            eprintln!("Error: empty code string");
            return 1;
        }
        (args[1].clone(), 2)
    };

    // Scan for --tools and --mcp flags
    let (tools_config_path, mcp_config_path, args) = {
        let mut tools_path: Option<String> = None;
        let mut mcp_path: Option<String> = None;
        let mut filtered: Vec<String> = Vec::with_capacity(args.len());
        let mut i = 0;
        while i < args.len() {
            if args[i] == "--tools" {
                if i + 1 < args.len() {
                    tools_path = Some(args[i + 1].clone());
                    i += 2;
                } else {
                    eprintln!("error: --tools requires a path argument");
                    return 1;
                }
            } else if args[i] == "--mcp" {
                if i + 1 < args.len() {
                    mcp_path = Some(args[i + 1].clone());
                    i += 2;
                } else {
                    eprintln!("error: --mcp requires a path argument");
                    return 1;
                }
            } else {
                filtered.push(args[i].clone());
                i += 1;
            }
        }
        if tools_path.is_some() && mcp_path.is_some() {
            eprintln!("error: --tools and --mcp are mutually exclusive");
            return 1;
        }
        (tools_path, mcp_path, filtered)
    };

    // Build RunArgs from positional args
    // Determine engine, emit, explain, dense, expanded, bench flags from remaining args
    let m = mode_args_start;
    let (engine_flag, run_rest_start) = if args.len() > m {
        match args[m].as_str() {
            "--run-cranelift" => (Some(cli::Engine::Cranelift), m + 1),
            "--run-llvm" => (Some(cli::Engine::Llvm), m + 1),
            "--run-vm" => (Some(cli::Engine::Vm), m + 1),
            "--run" | "--run-tree" => (Some(cli::Engine::Tree), m + 1),
            _ => (None, m),
        }
    } else {
        (None, m)
    };

    // Merge in any --run-* flag extracted from a non-canonical position
    // (before the source, or after positional func/args).
    let engine_flag = engine_flag.or(pre_engine);

    // Check for mode flags at the start of remaining args
    if args.len() > m {
        match args[m].as_str() {
            "--bench" => {
                let run_args = cli::RunArgs {
                    source,
                    engine: cli::Engine::Default,
                    run_tree: false,
                    run: false,
                    run_vm: false,
                    run_cranelift: false,
                    run_llvm: false,
                    bench: true,
                    emit: None,
                    explain: false,
                    dense: false,
                    expanded: false,
                    ast: false,
                    tools_path: tools_config_path,
                    mcp_path: mcp_config_path,
                    rest: args[m + 1..].to_vec(),
                };
                return dispatch_run(run_args, mode, explicit_json, no_hints);
            }
            "--explain" | "-x" if engine_flag.is_none() => {
                let run_args = cli::RunArgs {
                    source,
                    engine: cli::Engine::Default,
                    run_tree: false,
                    run: false,
                    run_vm: false,
                    run_cranelift: false,
                    run_llvm: false,
                    bench: false,
                    emit: None,
                    explain: true,
                    dense: false,
                    expanded: false,
                    ast: false,
                    tools_path: tools_config_path,
                    mcp_path: mcp_config_path,
                    rest: vec![],
                };
                return dispatch_run(run_args, mode, explicit_json, no_hints);
            }
            "--emit" if engine_flag.is_none() => {
                let target = if args.len() > m + 1 {
                    Some(args[m + 1].clone())
                } else {
                    None
                };
                let run_args = cli::RunArgs {
                    source,
                    engine: cli::Engine::Default,
                    run_tree: false,
                    run: false,
                    run_vm: false,
                    run_cranelift: false,
                    run_llvm: false,
                    bench: false,
                    emit: target,
                    explain: false,
                    dense: false,
                    expanded: false,
                    ast: false,
                    tools_path: tools_config_path,
                    mcp_path: mcp_config_path,
                    rest: vec![],
                };
                return dispatch_run(run_args, mode, explicit_json, no_hints);
            }
            "--dense" | "-d" | "--fmt" if engine_flag.is_none() => {
                let run_args = cli::RunArgs {
                    source,
                    engine: cli::Engine::Default,
                    run_tree: false,
                    run: false,
                    run_vm: false,
                    run_cranelift: false,
                    run_llvm: false,
                    bench: false,
                    emit: None,
                    explain: false,
                    dense: true,
                    expanded: false,
                    ast: false,
                    tools_path: tools_config_path,
                    mcp_path: mcp_config_path,
                    rest: vec![],
                };
                return dispatch_run(run_args, mode, explicit_json, no_hints);
            }
            "--expanded" | "-e" | "--fmt-expanded" if engine_flag.is_none() => {
                let run_args = cli::RunArgs {
                    source,
                    engine: cli::Engine::Default,
                    run_tree: false,
                    run: false,
                    run_vm: false,
                    run_cranelift: false,
                    run_llvm: false,
                    bench: false,
                    emit: None,
                    explain: false,
                    dense: false,
                    expanded: true,
                    ast: false,
                    tools_path: tools_config_path,
                    mcp_path: mcp_config_path,
                    rest: vec![],
                };
                return dispatch_run(run_args, mode, explicit_json, no_hints);
            }
            _ => {}
        }
    }

    // Default: build RunArgs with engine and remaining positional args
    let engine = engine_flag.unwrap_or(cli::Engine::Default);
    let rest_start = if engine_flag.is_some() {
        run_rest_start
    } else {
        m
    };
    let rest: Vec<String> = args[rest_start..].to_vec();

    let run_args = cli::RunArgs {
        source,
        engine,
        run_tree: false,
        run: false,
        run_vm: false,
        run_cranelift: false,
        run_llvm: false,
        bench: false,
        emit: None,
        explain: false,
        dense: false,
        expanded: false,
        ast: pre_ast,
        tools_path: tools_config_path,
        mcp_path: mcp_config_path,
        rest,
    };
    dispatch_run(run_args, mode, explicit_json, no_hints)
}

/// Dispatch the `run` subcommand via parsed RunArgs.  Returns exit code.
fn dispatch_run(r: cli::RunArgs, mode: OutputMode, explicit_json: bool, no_hints: bool) -> i32 {
    let source_arg = &r.source;

    // Read source from file or treat as inline code
    let (source, is_file) = if std::path::Path::new(source_arg).is_file() {
        let s = match std::fs::read_to_string(source_arg) {
            Ok(s) => s,
            Err(e) => {
                eprintln!("Error reading {}: {}", source_arg, e);
                return 1;
            }
        };
        (s, true)
    } else {
        if source_arg.is_empty() {
            eprintln!("Error: empty code string");
            return 1;
        }
        (source_arg.clone(), false)
    };

    let tools_config_path = r.tools_path.clone();
    let mcp_config_path = r.mcp_path.clone();

    if tools_config_path.is_some() && mcp_config_path.is_some() {
        eprintln!("error: --tools and --mcp are mutually exclusive");
        return 1;
    }

    warn_cross_language_syntax(&source, mode);

    let tokens = match lexer::lex(&source) {
        Ok(t) => t,
        Err(e) => {
            report_diagnostic(&Diagnostic::from(&e).with_source(source.clone()), mode);
            return 1;
        }
    };

    let token_spans: Vec<(lexer::Token, ast::Span)> = tokens
        .into_iter()
        .map(|(t, r)| {
            (
                t,
                ast::Span {
                    start: r.start,
                    end: r.end,
                },
            )
        })
        .collect();

    let (mut program, parse_errors) = parser::parse(token_spans);
    ast::resolve_aliases(&mut program);
    ast::desugar_dot_var_index(&mut program);
    program.source = Some(source.clone());

    // MCP injection
    #[cfg(not(feature = "tools"))]
    if mcp_config_path.is_some() {
        eprintln!(
            "error: --mcp requires the 'tools' feature (build with: cargo build --features tools)"
        );
        return 1;
    }

    #[cfg(feature = "tools")]
    let mut mcp_rt: Option<tokio::runtime::Runtime> = None;
    #[cfg(feature = "tools")]
    let mut mcp_provider_holder: Option<tools::mcp_provider::McpProvider> = None;

    #[cfg(feature = "tools")]
    if let Some(ref path) = mcp_config_path {
        let config = match tools::mcp_provider::McpConfig::from_file(path) {
            Ok(c) => c,
            Err(e) => {
                eprintln!("{}", e);
                return 1;
            }
        };
        let rt = tokio::runtime::Builder::new_current_thread()
            .enable_all()
            .build()
            .expect("tokio runtime");
        let provider = match rt.block_on(tools::mcp_provider::McpProvider::connect(&config)) {
            Ok(p) => p,
            Err(e) => {
                eprintln!("MCP error: {}", e);
                return 1;
            }
        };
        let mut decls = provider.tool_decls();
        decls.append(&mut program.declarations);
        program.declarations = decls;
        mcp_rt = Some(rt);
        mcp_provider_holder = Some(provider);
    }

    let mut had_errors = false;

    // Resolve imports
    {
        let base_dir: Option<std::path::PathBuf> = if is_file {
            std::path::Path::new(source_arg)
                .canonicalize()
                .ok()
                .and_then(|p| p.parent().map(|d| d.to_path_buf()))
        } else {
            None
        };
        let mut import_diagnostics: Vec<Diagnostic> = Vec::new();
        let mut visited = std::collections::HashSet::new();
        if let Ok(canonical_file) = std::path::Path::new(source_arg).canonicalize() {
            visited.insert(canonical_file);
        }
        program.declarations = resolve_imports(
            program.declarations,
            base_dir.as_deref(),
            &mut visited,
            &mut import_diagnostics,
        );
        for d in import_diagnostics {
            report_diagnostic(&d, mode);
            had_errors = true;
        }
    }

    for e in &parse_errors {
        report_diagnostic(&Diagnostic::from(e).with_source(source.clone()), mode);
        had_errors = true;
    }

    // AST-dump mode: explicit (`--ast`) OR the legacy inline-no-func default
    // (`ilo '<code>'` with no entry point and no other mode flag). This is an
    // inspection path, not an execution path, so verify (which exists to gate
    // execution) shouldn't gate it. Skipping verify here also avoids
    // false-positive errors on builtins or partial snippets that users want to
    // explore via the AST dump. Parse errors still gate (we can't dump an AST
    // we couldn't parse).
    let ast_dump_mode = r.ast
        || (!is_file
            && r.rest.is_empty()
            && !r.bench
            && !r.explain
            && r.emit.is_none()
            && !r.dense
            && !r.expanded
            && matches!(r.effective_engine(), cli::Engine::Default));

    if !ast_dump_mode {
        let verify_result = verify::verify(&program);
        for w in &verify_result.warnings {
            report_diagnostic(&Diagnostic::from(w).with_source(source.clone()), mode);
        }
        if !verify_result.errors.is_empty() {
            for e in &verify_result.errors {
                report_diagnostic(&Diagnostic::from(e).with_source(source.clone()), mode);
            }
            had_errors = true;
        }
    }

    if had_errors {
        return 1;
    }

    // Dispatch based on mode flags
    let exit_code = if r.bench {
        let func_name = r.rest.first().map(|s| s.as_str());
        let raw = if r.rest.len() > 1 {
            &r.rest[1..]
        } else {
            &[][..]
        };
        let run_args = parse_cli_args_typed(&program, func_name, raw);
        run_bench(&program, func_name, &run_args);
        0
    } else if r.explain {
        let filename = if is_file {
            Some(source_arg.as_str())
        } else {
            None
        };
        print!("{}", codegen::explain::explain(&program, filename));
        0
    } else if let Some(ref target) = r.emit {
        if target == "python" {
            println!("{}", codegen::python::emit(&program));
            0
        } else {
            eprintln!("Unknown emit target. Supported: python");
            1
        }
    } else if r.dense {
        println!(
            "{}",
            codegen::fmt::format(&program, codegen::fmt::FmtMode::Dense)
        );
        0
    } else if r.expanded {
        print!(
            "{}",
            codegen::fmt::format(&program, codegen::fmt::FmtMode::Expanded)
        );
        0
    } else {
        // Execution dispatch based on engine
        let engine = r.effective_engine();
        let rest = &r.rest;

        match engine {
            cli::Engine::Cranelift => {
                run_cranelift_engine(&program, rest, &source, mode, explicit_json)
            }
            cli::Engine::Llvm => run_llvm_engine(&program, rest),
            cli::Engine::Vm => {
                let func_name = rest.first().map(|s| s.as_str());
                let raw = if rest.len() > 1 { &rest[1..] } else { &[][..] };
                let run_args = parse_cli_args_typed(&program, func_name, raw);
                let compiled = match vm::compile(&program) {
                    Ok(c) => c,
                    Err(e) => {
                        eprintln!("Compile error: {}", e);
                        return 1;
                    }
                };
                let suppress = program_result_should_suppress(&program, func_name);
                run_vm_with_provider(
                    &compiled,
                    func_name,
                    run_args,
                    tools_config_path.as_deref(),
                    #[cfg(feature = "tools")]
                    mcp_provider_holder.as_ref(),
                    #[cfg(feature = "tools")]
                    mcp_rt.as_ref(),
                    &source,
                    mode,
                    explicit_json,
                    suppress,
                )
            }
            cli::Engine::Tree => {
                let func_name = rest.first().map(|s| s.as_str());
                let raw = if rest.len() > 1 { &rest[1..] } else { &[][..] };
                let run_args = parse_cli_args_typed(&program, func_name, raw);
                run_interp_with_provider(
                    &program,
                    func_name,
                    run_args,
                    tools_config_path.as_deref(),
                    #[cfg(feature = "tools")]
                    mcp_provider_holder,
                    #[cfg(feature = "tools")]
                    mcp_rt,
                    &source,
                    mode,
                    explicit_json,
                )
            }
            cli::Engine::Default => {
                // Default: func-name heuristic + Cranelift JIT with interpreter fallback.
                //
                // Inline-lambda lifting emits synthetic `__lit_N` top-level
                // decls (see parser/mod.rs ~line 2863). These are an
                // implementation detail of HOF dispatch — they must not show
                // up in the "available functions" listing, must not satisfy
                // the auto-run heuristic, and must not be selectable as a
                // CLI positional arg. The `__` prefix is reserved for the
                // compiler; filtering on it is safe.
                let func_names: Vec<&str> = program
                    .declarations
                    .iter()
                    .filter_map(|d| match d {
                        ast::Decl::Function { name, .. } if !name.starts_with("__") => {
                            Some(name.as_str())
                        }
                        _ => None,
                    })
                    .collect();

                // Explicit AST dump (`--ast`) takes precedence over everything.
                if r.ast {
                    return dump_ast_json(&program);
                }

                let (func_name, run_args) = if let Some(first) = rest.first() {
                    if func_names.contains(&first.as_str()) {
                        let fn_ref = Some(first.as_str());
                        (fn_ref, parse_cli_args_typed(&program, fn_ref, &rest[1..]))
                    } else {
                        (None, rest.iter().map(|a| parse_cli_arg(a)).collect())
                    }
                } else if is_file {
                    // File with no func arg: auto-run if there's exactly one
                    // function, auto-run `main` if a multi-fn file defines
                    // one, list available functions if there are several
                    // without a `main`, AST-dump if there are none
                    // (declarations-only file — useful for inspecting
                    // type/alias-only modules). SKILL.md documents the
                    // main-as-default convention; see `[CLI invocation]`.
                    match func_names.len() {
                        0 => return dump_ast_json(&program),
                        1 => (None, vec![]),
                        _ if func_names.contains(&"main") => (Some("main"), vec![]),
                        _ => {
                            eprintln!(
                                "error: {} defines multiple functions, please specify one.",
                                source_arg
                            );
                            eprintln!("available functions:");
                            for n in &func_names {
                                eprintln!("  {}", n);
                            }
                            eprintln!();
                            eprintln!("  ilo {} <func> [args...]   run a function", source_arg);
                            eprintln!(
                                "  ilo --ast {}              dump the parsed AST as JSON",
                                source_arg
                            );
                            return 1;
                        }
                    }
                } else {
                    // Inline code with no func arg and no other mode flag.
                    //
                    // SKILL.md documents: "Inline programs (`ilo 'code'`)
                    // and single-function files run their entry function
                    // with the remaining CLI args; no explicit function
                    // name needed." Auto-run when there's a runnable
                    // target: a function called `main`, or a single
                    // user-defined function.
                    //
                    // Silently AST-dumping a runnable inline program was a
                    // soundness hazard for piped consumers — they got
                    // valid-looking JSON on stdout with exit code 0 that
                    // was NOT the program result.
                    //
                    // Zero-fn or multi-fn-without-main inline snippets
                    // still AST-dump, preserving the tooling escape hatch
                    // from PR #178. `--ast` remains the explicit form for
                    // pinning AST-dump output regardless of fn shape.
                    match func_names.len() {
                        0 => return dump_ast_json(&program),
                        1 => (None, vec![]),
                        _ if func_names.contains(&"main") => (Some("main"), vec![]),
                        _ => return dump_ast_json(&program),
                    }
                };

                run_default(&program, func_name, run_args, &source, mode, explicit_json)
            }
        }
    };

    // Emit idiomatic hints after successful execution
    if exit_code == 0 && !no_hints {
        let hints = collect_hints_with_program(&source, Some(&program));
        emit_hints(&hints, mode);
    }

    exit_code
}

/// Cranelift JIT engine dispatch. Returns exit code.
fn run_cranelift_engine(
    program: &ast::Program,
    rest: &[String],
    source: &str,
    mode: OutputMode,
    explicit_json: bool,
) -> i32 {
    let func_name = rest.first().map(|s| s.as_str());
    let raw = if rest.len() > 1 { &rest[1..] } else { &[][..] };
    let run_args = parse_cli_args_typed(program, func_name, raw);
    let suppress = program_result_should_suppress(program, func_name);

    #[cfg(feature = "cranelift")]
    {
        let compiled = match vm::compile(program) {
            Ok(c) => c,
            Err(e) => {
                eprintln!("Compile error: {}", e);
                return 1;
            }
        };
        let target_name = func_name.unwrap_or(
            compiled
                .func_names
                .first()
                .map(|s| s.as_str())
                .unwrap_or("main"),
        );
        let func_idx = match compiled.func_names.iter().position(|n| n == target_name) {
            Some(i) => i,
            None => {
                eprintln!("undefined function: {}", target_name);
                return 1;
            }
        };
        let chunk = &compiled.chunks[func_idx];
        let nan_consts = &compiled.nan_constants[func_idx];
        let nan_args: Vec<u64> = run_args
            .iter()
            .map(|v| vm::NanVal::from_value_with_program(v, &compiled.func_names).0)
            .collect();
        match vm::jit_cranelift::compile_and_call(chunk, nan_consts, &nan_args, &compiled) {
            Ok(result_bits) => {
                // Use the program-aware bridge so user-fn FnRefs in the
                // returned value resolve back to their source names
                // rather than the synthetic `<user_fn:N>` placeholder.
                // `with_active_registry` clears its TLS on return, so
                // we cannot lean on the implicit context here.
                let result = vm::NanVal(result_bits).to_value_with_program(&compiled.func_names);
                print_value(&result, explicit_json, suppress);
                program_exit_code(&result)
            }
            Err(vm::jit_cranelift::JitCallError::Runtime(e)) => {
                report_diagnostic(&Diagnostic::from(&e).with_source(source.to_string()), mode);
                1
            }
            Err(vm::jit_cranelift::JitCallError::NotEligible) => {
                eprintln!("Cranelift JIT: compilation failed");
                1
            }
        }
    }
    #[cfg(not(feature = "cranelift"))]
    {
        let _ = (func_name, run_args, source, mode, explicit_json, suppress);
        eprintln!("Cranelift JIT not enabled. Build with: cargo build --features cranelift");
        1
    }
}

/// LLVM JIT engine dispatch. Returns exit code.
fn run_llvm_engine(_program: &ast::Program, rest: &[String]) -> i32 {
    let func_name = rest.first().map(|s| s.as_str());
    let jit_args: Vec<f64> = if rest.len() > 1 {
        let mut args = Vec::new();
        for a in &rest[1..] {
            match a.parse::<f64>() {
                Ok(v) => args.push(v),
                Err(_) => {
                    eprintln!("error: JIT argument '{}' is not a valid number", a);
                    return 1;
                }
            }
        }
        args
    } else {
        vec![]
    };

    #[cfg(feature = "llvm")]
    {
        let compiled = match vm::compile(program) {
            Ok(c) => c,
            Err(e) => {
                eprintln!("Compile error: {}", e);
                return 1;
            }
        };
        let target_name = func_name.unwrap_or(
            compiled
                .func_names
                .first()
                .map(|s| s.as_str())
                .unwrap_or("main"),
        );
        let func_idx = match compiled.func_names.iter().position(|n| n == target_name) {
            Some(i) => i,
            None => {
                eprintln!("undefined function: {}", target_name);
                return 1;
            }
        };
        let chunk = &compiled.chunks[func_idx];
        let nan_consts = &compiled.nan_constants[func_idx];
        match vm::jit_llvm::compile_and_call(chunk, nan_consts, &jit_args) {
            Some(result) => {
                if result == (result as i64) as f64 {
                    println!("{}", result as i64);
                } else {
                    println!("{}", result);
                }
                0
            }
            None => {
                eprintln!("LLVM JIT: function not eligible for compilation");
                1
            }
        }
    }
    #[cfg(not(feature = "llvm"))]
    {
        let _ = (func_name, jit_args);
        eprintln!("LLVM JIT not enabled. Build with: cargo build --features llvm");
        1
    }
}

/// Print the full help text (same as the old `ilo help` output).
fn print_help() {
    println!("ilo — a programming language for AI agents\n");
    println!("Usage:");
    println!("  ilo <code> [args...]              Run (Cranelift JIT, falls back to interpreter)");
    println!("  ilo <file.ilo> [args...]          Run from file");
    println!("  ilo <code> func [args...]         Run a specific function");
    println!("  ilo <code> --emit python          Transpile to Python");
    println!("  ilo <code> --explain / -x            Annotate each statement with its role");
    println!("  ilo <code> --dense / -d             Reformat (dense wire format)");
    println!("  ilo <code> --expanded / -e          Reformat (expanded human format)");
    println!("  ilo --ast <code-or-file>          Print AST as JSON");
    println!("  ilo <code> --bench func [args...] Benchmark a function");
    println!("  ilo repl                          Interactive REPL");
    println!("  ilo graph <file> [flags]          Dependency graph (JSON or DOT)");
    println!("  ilo help lang                     Show language specification");
    println!("  ilo help ai | ilo -ai             Compact spec for LLM consumption");
    println!("  ilo --explain ILO-T005            Explain an error code");
    println!("  ilo --version | -V                Print version\n");
    println!("Output format (errors):");
    println!("  --ansi / -a   Force ANSI colour output (default when stderr is a TTY)");
    println!("  --text / -t   Force plain text output (no colour)");
    println!("  --json / -j   Force JSON output (default when stderr is not a TTY)");
    println!("  --no-hints / -nh  Suppress idiomatic hints after execution");
    println!("  NO_COLOR=1    Disable colour (same as --text)\n");
    println!("Tool providers (requires --features tools build):");
    println!("  --tools <path>   HTTP tool provider config (JSON)");
    println!("  --mcp <path>     MCP server config (Claude Desktop format JSON)\n");
    println!("Tool discovery:");
    println!("  ilo tool -m <path>              List tools from MCP server");
    println!("  ilo tool -t <path>              List tools from HTTP config");
    println!("  ilo tool ... --full             Show full signatures");
    println!("  ilo tool ... --ilo              Output as valid ilo tool declarations");
    println!("  ilo tool ... --json             Output as JSON array\n");
    println!("Agent serve loop:");
    println!("  ilo serv [-m <path>] [-t <path>]");
    println!("  Request:  {{\"program\": \"<ilo>\", \"args\": [...], \"func\": \"name\"}}");
    println!(
        "  Response: {{\"ok\": <value>, \"ms\": n}} | {{\"error\": {{\"phase\": \"...\", ...}}}}\n"
    );
    println!("Dependency graph:");
    println!("  ilo graph <file>                    Full call graph (JSON)");
    println!("  ilo graph <file> --fn NAME          Subgraph for one function");
    println!("  ilo graph <file> --reverse          Reverse callers");
    println!("  ilo graph <file> --subgraph         Transitive dependencies");
    println!("  ilo graph <file> --budget N         Limit to N tokens of source");
    println!("  ilo graph <file> --dot              Output as DOT (Graphviz)\n");
    println!("AOT compilation:");
    println!("  ilo compile <file> [-o out] [func]  Compile to standalone binary\n");
    println!("Backends:");
    println!("  (default)        Cranelift JIT → interpreter fallback");
    println!("  --run-tree       Tree-walking interpreter");
    println!("  --run-vm         Register VM");
    println!("  --run-cranelift  Cranelift JIT");
    println!("  --run-llvm       LLVM JIT (requires --features llvm build)\n");
    println!("Examples:");
    println!("  ilo 'f x:n>n;*x 2' 5             Define and call f(5) → 10");
    println!("  ilo 'f xs:L n>n;len xs' 1,2,3     Pass a list → 3");
    println!("  ilo program.ilo 10 20             Run file with arguments");
    println!("  ilo 'f x:n>n;*x 2' --emit python Transpile to Python");
}

/// Dispatch --run-vm, routing to MCP / HTTP / plain run based on available providers.
/// Returns exit code.
#[allow(clippy::too_many_arguments)]
fn run_vm_with_provider(
    compiled: &vm::CompiledProgram,
    func_name: Option<&str>,
    args: Vec<interpreter::Value>,
    tools_config_path: Option<&str>,
    #[cfg(feature = "tools")] mcp_provider: Option<&tools::mcp_provider::McpProvider>,
    #[cfg(feature = "tools")] mcp_rt: Option<&tokio::runtime::Runtime>,
    source: &str,
    mode: OutputMode,
    explicit_json: bool,
    suppress_loop_tail: bool,
) -> i32 {
    #[cfg(feature = "tools")]
    if let Some(provider) = mcp_provider {
        let rt = mcp_rt.expect("runtime present with mcp_provider");
        match vm::run_with_tools(compiled, func_name, args, provider, rt) {
            Ok(val) => {
                print_value(&val, explicit_json, suppress_loop_tail);
                return program_exit_code(&val);
            }
            Err(e) => {
                report_diagnostic(&Diagnostic::from(&e).with_source(source.to_string()), mode);
                return 1;
            }
        }
    }

    if let Some(tools_path) = tools_config_path {
        let config = match tools::http_provider::ToolsConfig::from_file(tools_path) {
            Ok(c) => c,
            Err(e) => {
                eprintln!("{}", e);
                return 1;
            }
        };
        let provider = tools::http_provider::HttpProvider::new(config);
        #[cfg(feature = "tools")]
        let runtime = tokio::runtime::Builder::new_current_thread()
            .enable_all()
            .build()
            .expect("tokio runtime");
        return match vm::run_with_tools(
            compiled,
            func_name,
            args,
            &provider,
            #[cfg(feature = "tools")]
            &runtime,
        ) {
            Ok(val) => {
                print_value(&val, explicit_json, suppress_loop_tail);
                program_exit_code(&val)
            }
            Err(e) => {
                report_diagnostic(&Diagnostic::from(&e).with_source(source.to_string()), mode);
                1
            }
        };
    }

    match vm::run(compiled, func_name, args) {
        Ok(val) => {
            print_value(&val, explicit_json, suppress_loop_tail);
            program_exit_code(&val)
        }
        Err(e) => {
            report_diagnostic(&Diagnostic::from(&e).with_source(source.to_string()), mode);
            1
        }
    }
}

/// Dispatch --run-tree, routing to MCP / HTTP / plain run based on available providers.
/// Returns exit code.
#[allow(clippy::too_many_arguments)]
fn run_interp_with_provider(
    program: &ast::Program,
    func_name: Option<&str>,
    args: Vec<interpreter::Value>,
    tools_config_path: Option<&str>,
    #[cfg(feature = "tools")] mcp_provider: Option<tools::mcp_provider::McpProvider>,
    #[cfg(feature = "tools")] mcp_rt: Option<tokio::runtime::Runtime>,
    source: &str,
    mode: OutputMode,
    explicit_json: bool,
) -> i32 {
    let suppress = program_result_should_suppress(program, func_name);
    #[cfg(feature = "tools")]
    if let Some(provider) = mcp_provider {
        let rt = std::sync::Arc::new(mcp_rt.expect("runtime present with mcp_provider"));
        match interpreter::run_with_tools(
            program,
            func_name,
            args,
            std::sync::Arc::new(provider),
            rt,
        ) {
            Ok(val) => {
                print_value(&val, explicit_json, suppress);
                return program_exit_code(&val);
            }
            Err(e) => {
                report_diagnostic(&Diagnostic::from(&e).with_source(source.to_string()), mode);
                return 1;
            }
        }
    }

    if let Some(tools_path) = tools_config_path {
        let config = match tools::http_provider::ToolsConfig::from_file(tools_path) {
            Ok(c) => c,
            Err(e) => {
                eprintln!("{}", e);
                return 1;
            }
        };
        let provider = std::sync::Arc::new(tools::http_provider::HttpProvider::new(config));
        #[cfg(feature = "tools")]
        let runtime = std::sync::Arc::new(
            tokio::runtime::Builder::new_current_thread()
                .enable_all()
                .build()
                .expect("tokio runtime"),
        );
        return match interpreter::run_with_tools(
            program,
            func_name,
            args,
            provider,
            #[cfg(feature = "tools")]
            runtime,
        ) {
            Ok(val) => {
                print_value(&val, explicit_json, suppress);
                program_exit_code(&val)
            }
            Err(e) => {
                report_diagnostic(&Diagnostic::from(&e).with_source(source.to_string()), mode);
                1
            }
        };
    }

    match interpreter::run(program, func_name, args) {
        Ok(val) => {
            print_value(&val, explicit_json, suppress);
            program_exit_code(&val)
        }
        Err(e) => {
            report_diagnostic(&Diagnostic::from(&e).with_source(source.to_string()), mode);
            1
        }
    }
}

/// Serialize the program as pretty JSON to stdout. Used by the explicit
/// `--ast` flag and by the legacy inline-no-func default path.
fn dump_ast_json(program: &ast::Program) -> i32 {
    match serde_json::to_string_pretty(program) {
        Ok(json) => {
            println!("{}", json);
            0
        }
        Err(e) => {
            eprintln!("Serialization error: {}", e);
            1
        }
    }
}

fn run_default(
    program: &ast::Program,
    func_name: Option<&str>,
    args: Vec<interpreter::Value>,
    source: &str,
    mode: OutputMode,
    explicit_json: bool,
) -> i32 {
    let suppress = program_result_should_suppress(program, func_name);
    // Try Cranelift JIT first — all functions are now eligible
    #[cfg(feature = "cranelift")]
    {
        if let Ok(compiled) = vm::compile(program) {
            let target = func_name.unwrap_or(
                compiled
                    .func_names
                    .first()
                    .map(|s| s.as_str())
                    .unwrap_or("main"),
            );
            if let Some(func_idx) = compiled.func_names.iter().position(|n| n == target) {
                let chunk = &compiled.chunks[func_idx];
                let nan_consts = &compiled.nan_constants[func_idx];
                let nan_args: Vec<u64> = args
                    .iter()
                    .map(|v| vm::NanVal::from_value_with_program(v, &compiled.func_names).0)
                    .collect();
                match vm::jit_cranelift::compile_and_call(chunk, nan_consts, &nan_args, &compiled) {
                    Ok(result_bits) => {
                        // Use the program-aware bridge so a user-fn FnRef
                        // returned at the top-level resolves to its source
                        // name (`<fn:sq>`) rather than `<user_fn:0>`.
                        let result =
                            vm::NanVal(result_bits).to_value_with_program(&compiled.func_names);
                        print_value(&result, explicit_json, suppress);
                        return program_exit_code(&result);
                    }
                    Err(vm::jit_cranelift::JitCallError::Runtime(e)) => {
                        // The JIT executed and surfaced a defined runtime
                        // error (e.g. `hd []`, `at xs 99`). Do NOT fall back
                        // to the tree interpreter — it would hide the error
                        // or, worse, run the program a second time and
                        // produce divergent observable behaviour.
                        report_diagnostic(
                            &Diagnostic::from(&e).with_source(source.to_string()),
                            mode,
                        );
                        return 1;
                    }
                    Err(vm::jit_cranelift::JitCallError::NotEligible) => {
                        // JIT couldn't dispatch this function — fall through
                        // to the tree interpreter as before.
                    }
                }
            }
        }
    }

    // Fall back to interpreter
    match interpreter::run(program, func_name, args) {
        Ok(val) => {
            print_value(&val, explicit_json, suppress);
            program_exit_code(&val)
        }
        Err(e) => {
            report_diagnostic(&Diagnostic::from(&e).with_source(source.to_string()), mode);
            1
        }
    }
}

/// Walk a body looking for any `ret` or braceless guard — these short-circuit the
/// function and mean the program's return value did not come from the body-tail.
fn body_has_early_return(body: &[ast::Spanned<ast::Stmt>]) -> bool {
    for s in body {
        if stmt_has_early_return(&s.node) {
            return true;
        }
    }
    false
}

fn stmt_has_early_return(stmt: &ast::Stmt) -> bool {
    match stmt {
        ast::Stmt::Return(_) => true,
        // Braceless guards (`cond expr`) early-return from the function.
        ast::Stmt::Guard {
            braceless: true, ..
        } => true,
        // Braced guards do NOT early-return, but their bodies might contain `ret`.
        ast::Stmt::Guard {
            body, else_body, ..
        } => {
            body_has_early_return(body)
                || else_body.as_ref().is_some_and(|b| body_has_early_return(b))
        }
        ast::Stmt::Match { arms, .. } => arms.iter().any(|a| body_has_early_return(&a.body)),
        ast::Stmt::ForEach { body, .. }
        | ast::Stmt::ForRange { body, .. }
        | ast::Stmt::While { body, .. } => body_has_early_return(body),
        _ => false,
    }
}

/// Top-level auto-print suppression rule for the program's final value.
///
/// Returns true when the program's syntactic entry-function body ends with a
/// `@`/`wh` loop AND has no early-return path. In that case the loop's
/// last-body-value bubbles up as the program result, and re-printing it on top
/// of whatever the loop body already printed (e.g. via `prnt`) just duplicates
/// the last item. Functions are still free to use loop-as-expression value
/// internally; this is purely about the final stdout line at the top level.
fn program_result_should_suppress(program: &ast::Program, func_name: Option<&str>) -> bool {
    let entry_body: Option<&Vec<ast::Spanned<ast::Stmt>>> = match func_name {
        Some(name) => program.declarations.iter().find_map(|d| match d {
            ast::Decl::Function { name: n, body, .. } if n == name => Some(body),
            _ => None,
        }),
        None => program.declarations.iter().find_map(|d| match d {
            ast::Decl::Function { body, .. } => Some(body),
            _ => None,
        }),
    };
    let Some(body) = entry_body else {
        return false;
    };
    let Some(last) = body.last() else {
        return false;
    };
    let ends_with_loop = matches!(
        last.node,
        ast::Stmt::ForEach { .. } | ast::Stmt::ForRange { .. } | ast::Stmt::While { .. }
    );
    if !ends_with_loop {
        return false;
    }
    // Only suppress when the entry body has no early-return path. With an
    // early-return present (`ret`, braceless guard) we can't tell at print
    // time whether the value came from the loop tail or from an explicit
    // return, so we err on the side of printing.
    !body_has_early_return(body)
}

/// Print a program result value. When `as_json` is true (explicit -j/--json), wraps it as
/// `{"ok": ...}` or `{"error": ...}`. Auto-detected JSON mode does not affect result format.
///
/// In plain (non-JSON) mode, suppresses the line entirely when
/// `suppress_loop_tail` is true — see [`program_result_should_suppress`] for
/// the rule. A bare Nil that came from an *explicit* return (e.g. a function
/// declared `>O n` returning `nil`) is still printed, because the user asked
/// for it. JSON mode is unchanged so machine-readable consumers always get a
/// structured result.
///
/// `Value::Err(_)` is routed to stderr in plain mode (matching `report_diagnostic`'s
/// stream convention for failures). In JSON mode the `{"error": ...}` envelope is
/// still written to stdout, so machine consumers can keep parsing stdout uniformly
/// and discriminate on the top-level key.
fn print_value(val: &interpreter::Value, as_json: bool, suppress_loop_tail: bool) {
    if !as_json {
        // Value::Err always prints to stderr — even when suppress_loop_tail
        // is on. The loop-tail suppression rule exists to avoid duplicating
        // the loop body's `prnt` output as a final stdout line for happy-path
        // tail values; it must not silently swallow a program failure. The
        // companion exit-code surfacing happens in `program_exit_code`, so
        // skipping the err here would leave the operator with `exit 1` and
        // zero diagnostic context.
        if matches!(val, interpreter::Value::Err(_)) {
            eprintln!("{}", val);
            return;
        }
        if suppress_loop_tail {
            return;
        }
        // Top-level `Value::Ok(inner)` prints the inner value bare — no `~`
        // prefix. Symmetric with the `Value::Err` split above (PR #255): `^e`
        // goes to stderr with exit 1, so `~v` goes to stdout (inner) with
        // exit 0. Bash callers piping a Result-returning ilo program no longer
        // have to strip a leading `~` to consume the value.
        //
        // This applies only to the top-level program return. `Display` on
        // `Value::Ok` still renders `~v` everywhere else (nested values,
        // `prnt ~"x"`, REPL prompts, error messages, debug formatting) — those
        // contexts genuinely want the wrapper visible.
        if let interpreter::Value::Ok(inner) = val {
            println!("{}", inner);
            return;
        }
        println!("{}", val);
        return;
    }
    let json = match val {
        interpreter::Value::Ok(inner) => {
            let v = inner.to_json().unwrap_or(serde_json::Value::Null);
            serde_json::json!({"ok": v})
        }
        interpreter::Value::Err(inner) => {
            let v = inner
                .to_json()
                .unwrap_or_else(|_| serde_json::Value::String(inner.to_string()));
            serde_json::json!({"error": {"phase": "program", "value": v}})
        }
        other => {
            let v = other
                .to_json()
                .unwrap_or_else(|_| serde_json::Value::String(other.to_string()));
            serde_json::json!({"ok": v})
        }
    };
    println!("{}", json);
}

/// Exit code for a program's top-level result. `Value::Err(_)` from `main` (or any
/// entry function) must surface as a non-zero exit so shell pipelines and CI can
/// detect failure — this is the companion to [#248]'s `!!` panic-unwrap fix, which
/// addressed the explicit-crash path. Returning the error variant from the `~`/`^`
/// arm without `!!` is the same kind of failure semantically, just with a value.
fn program_exit_code(val: &interpreter::Value) -> i32 {
    if matches!(val, interpreter::Value::Err(_)) {
        1
    } else {
        0
    }
}

#[allow(unused_variables, unused_mut)]
fn run_bench(program: &ast::Program, func_name: Option<&str>, args: &[interpreter::Value]) {
    use std::io::Write;
    use std::process::Command;
    use std::time::Instant;

    let iterations: u32 = 10_000;

    // -- Rust interpreter benchmark --
    // Warmup
    for _ in 0..100 {
        let _ = interpreter::run(program, func_name, args.to_vec());
    }

    let start = Instant::now();
    let mut result = interpreter::Value::Nil;
    for _ in 0..iterations {
        result = interpreter::run(program, func_name, args.to_vec())
            .expect("interpreter error during benchmark");
    }
    let interp_dur = start.elapsed();
    let interp_ns = interp_dur.as_nanos() / iterations as u128;

    println!("Rust interpreter");
    println!("  result:     {}", result);
    println!("  iterations: {}", iterations);
    println!("  total:      {:.2}ms", interp_dur.as_nanos() as f64 / 1e6);
    println!("  per call:   {}ns", interp_ns);
    println!();

    // -- Register VM benchmark --
    let compiled = vm::compile(program).expect("compile error in benchmark");
    // Warmup
    for _ in 0..100 {
        let _ = vm::run(&compiled, func_name, args.to_vec());
    }

    let start = Instant::now();
    let mut vm_result = interpreter::Value::Nil;
    for _ in 0..iterations {
        vm_result =
            vm::run(&compiled, func_name, args.to_vec()).expect("VM error during benchmark");
    }
    let vm_dur = start.elapsed();
    let vm_ns = vm_dur.as_nanos() / iterations as u128;

    println!("Register VM");
    println!("  result:     {}", vm_result);
    println!("  iterations: {}", iterations);
    println!("  total:      {:.2}ms", vm_dur.as_nanos() as f64 / 1e6);
    println!("  per call:   {}ns", vm_ns);
    println!();

    // -- Register VM (reusable) benchmark --
    let call_name = func_name.unwrap_or(
        compiled
            .func_names
            .first()
            .map(|s| s.as_str())
            .unwrap_or("main"),
    );
    let mut vm_state = vm::VmState::new(&compiled);
    for _ in 0..100 {
        let _ = vm_state.call(call_name, args.to_vec());
    }

    let start = Instant::now();
    for _ in 0..iterations {
        vm_result = vm_state
            .call(call_name, args.to_vec())
            .expect("VM reusable error during benchmark");
    }
    let vm_reuse_dur = start.elapsed();
    let vm_reuse_ns = vm_reuse_dur.as_nanos() / iterations as u128;

    println!("Register VM (reusable)");
    println!("  result:     {}", vm_result);
    println!("  iterations: {}", iterations);
    println!(
        "  total:      {:.2}ms",
        vm_reuse_dur.as_nanos() as f64 / 1e6
    );
    println!("  per call:   {}ns", vm_reuse_ns);
    println!();

    // -- JIT benchmarks --
    // Extract function info for JIT
    let call_name_jit = func_name.unwrap_or(
        compiled
            .func_names
            .first()
            .map(|s| s.as_str())
            .unwrap_or("main"),
    );
    let func_idx_jit = compiled.func_names.iter().position(|n| n == call_name_jit);
    #[cfg(feature = "llvm")]
    let jit_args: Vec<f64> = args
        .iter()
        .filter_map(|a| match a {
            interpreter::Value::Number(n) => Some(*n),
            _ => None,
        })
        .collect();
    #[cfg(feature = "llvm")]
    let all_numeric = jit_args.len() == args.len();
    let mut jit_cranelift_ns: Option<u128> = None;
    #[cfg(feature = "cranelift")]
    if let Some(fi) = func_idx_jit {
        let chunk = &compiled.chunks[fi];
        let nan_consts = &compiled.nan_constants[fi];
        let nan_args: Vec<u64> = args.iter().map(|v| vm::NanVal::from_value(v).0).collect();
        vm::with_active_registry(&compiled, || {
            if let Some(jit_func) = vm::jit_cranelift::compile(chunk, nan_consts, &compiled) {
                for _ in 0..100 {
                    let _ = vm::jit_cranelift::call(&jit_func, &nan_args);
                }

                let start = Instant::now();
                let mut jit_result_bits = 0u64;
                for _ in 0..iterations {
                    jit_result_bits = vm::jit_cranelift::call(&jit_func, &nan_args)
                        .expect("Cranelift JIT error during benchmark");
                }
                let jit_dur = start.elapsed();
                let ns = jit_dur.as_nanos() / iterations as u128;
                jit_cranelift_ns = Some(ns);

                // Program-aware bridge so a benchmarked entry that returns
                // a user-fn FnRef renders as `<fn:name>` instead of the
                // synthetic `<user_fn:N>` placeholder.
                let jit_result =
                    vm::NanVal(jit_result_bits).to_value_with_program(&compiled.func_names);
                println!("Cranelift JIT");
                println!("  result:     {}", jit_result);
                println!("  iterations: {}", iterations);
                println!("  total:      {:.2}ms", jit_dur.as_nanos() as f64 / 1e6);
                println!("  per call:   {}ns", ns);
                println!();
            }
        });
    }

    #[allow(unused_variables)]
    let jit_llvm_ns: Option<u128> = None;
    #[cfg(feature = "llvm")]
    if let Some(fi) = func_idx_jit {
        if all_numeric {
            let chunk = &compiled.chunks[fi];
            let nan_consts = &compiled.nan_constants[fi];
            if let Some(jit_func) = vm::jit_llvm::compile(chunk, nan_consts) {
                for _ in 0..100 {
                    let _ = vm::jit_llvm::call(&jit_func, &jit_args);
                }

                let start = Instant::now();
                let mut jit_result = 0.0f64;
                for _ in 0..iterations {
                    jit_result = vm::jit_llvm::call(&jit_func, &jit_args)
                        .expect("LLVM JIT error during benchmark");
                }
                let jit_dur = start.elapsed();
                let ns = jit_dur.as_nanos() / iterations as u128;
                jit_llvm_ns = Some(ns);

                println!("LLVM JIT");
                if jit_result == (jit_result as i64) as f64 {
                    println!("  result:     {}", jit_result as i64);
                } else {
                    println!("  result:     {}", jit_result);
                }
                println!("  iterations: {}", iterations);
                println!("  total:      {:.2}ms", jit_dur.as_nanos() as f64 / 1e6);
                println!("  per call:   {}ns", ns);
                println!();
            }
        }
    }

    // -- Python transpiler benchmark (single invocation) --
    let py_code = codegen::python::emit(program);
    let call_func = func_name.unwrap_or("main").replace('-', "_");
    let call_args: Vec<String> = args
        .iter()
        .map(|a| match a {
            interpreter::Value::Number(n) => {
                if *n == (*n as i64) as f64 {
                    format!("{}", *n as i64)
                } else {
                    format!("{}", n)
                }
            }
            interpreter::Value::Text(s) => format!("\"{}\"", s),
            interpreter::Value::Bool(b) => {
                if *b {
                    "True".to_string()
                } else {
                    "False".to_string()
                }
            }
            _ => "None".to_string(),
        })
        .collect();

    // Python script: prints human-readable lines then a final __NS__=<value> for parsing
    let py_script = format!(
        r#"import time
{code}
_n = {n}
for _ in range(100):
    {func}({args})
_start = time.perf_counter_ns()
for _ in range(_n):
    _r = {func}({args})
_elapsed = time.perf_counter_ns() - _start
_per = _elapsed // _n
print(f"result:     {{_r}}")
print(f"iterations: {{_n}}")
print(f"total:      {{_elapsed / 1e6:.2f}}ms")
print(f"per call:   {{_per}}ns")
print(f"__NS__={{_per}}")
"#,
        code = py_code,
        n = iterations,
        func = call_func,
        args = call_args.join(", ")
    );

    println!("Python transpiled");
    let output = Command::new("python3").arg("-c").arg(&py_script).output();

    let mut py_ns: Option<u128> = None;
    match output {
        Ok(out) => {
            let stdout = String::from_utf8_lossy(&out.stdout);
            for line in stdout.lines() {
                if let Some(val) = line.strip_prefix("__NS__=") {
                    py_ns = val.parse().ok();
                } else {
                    println!("  {}", line);
                }
            }
            std::io::stderr()
                .write_all(&out.stderr)
                .expect("write to stderr");
        }
        Err(e) => eprintln!("  failed to run python3: {}", e),
    }

    println!();

    // -- Summary --
    println!("Summary");
    if vm_ns > 0 && interp_ns > 0 {
        if vm_ns < interp_ns {
            println!(
                "  Register VM is {:.1}x faster than interpreter",
                interp_ns as f64 / vm_ns as f64
            );
        } else {
            println!(
                "  Interpreter is {:.1}x faster than bytecode VM",
                vm_ns as f64 / interp_ns as f64
            );
        }
    }
    if let Some(jit_ns) = jit_cranelift_ns
        && jit_ns > 0
        && vm_reuse_ns > 0
    {
        println!(
            "  Cranelift JIT is {:.1}x faster than VM (reusable)",
            vm_reuse_ns as f64 / jit_ns as f64
        );
    }
    if let Some(jit_ns) = jit_llvm_ns
        && jit_ns > 0
        && vm_reuse_ns > 0
    {
        println!(
            "  LLVM JIT is {:.1}x faster than VM (reusable)",
            vm_reuse_ns as f64 / jit_ns as f64
        );
    }
    if let Some(py) = py_ns {
        if interp_ns > 0 && py > 0 {
            if interp_ns < py {
                println!(
                    "  Rust interpreter is {:.1}x faster than Python",
                    py as f64 / interp_ns as f64
                );
            } else {
                println!(
                    "  Python is {:.1}x faster than Rust interpreter",
                    interp_ns as f64 / py as f64
                );
            }
        }
        if vm_ns > 0 && py > 0 {
            if vm_ns < py {
                println!(
                    "  Register VM is {:.1}x faster than Python",
                    py as f64 / vm_ns as f64
                );
            } else {
                println!(
                    "  Python is {:.1}x faster than Register VM",
                    vm_ns as f64 / py as f64
                );
            }
        }
        if vm_reuse_ns > 0 && py > 0 {
            if vm_reuse_ns < py {
                println!(
                    "  VM (reusable) is {:.1}x faster than Python",
                    py as f64 / vm_reuse_ns as f64
                );
            } else {
                println!(
                    "  Python is {:.1}x faster than VM (reusable)",
                    vm_reuse_ns as f64 / py as f64
                );
            }
        }
        if let Some(jit_ns) = jit_cranelift_ns
            && jit_ns > 0
            && py > 0
        {
            println!(
                "  Cranelift JIT is {:.1}x faster than Python",
                py as f64 / jit_ns as f64
            );
        }
        if let Some(jit_ns) = jit_llvm_ns
            && jit_ns > 0
            && py > 0
        {
            println!(
                "  LLVM JIT is {:.1}x faster than Python",
                py as f64 / jit_ns as f64
            );
        }
    }
}

/// Split a string on top-level commas, respecting [] nesting.
/// Used by `parse_cli_arg` so that nested-list literals like
/// `[[1,2],[3,4]]` are parsed as two elements rather than four.
fn split_top_level_commas(s: &str) -> Vec<&str> {
    let mut parts = Vec::new();
    let mut depth: i32 = 0;
    let mut start = 0usize;
    let bytes = s.as_bytes();
    for (i, &b) in bytes.iter().enumerate() {
        match b {
            b'[' => depth += 1,
            b']' => depth -= 1,
            b',' if depth == 0 => {
                parts.push(&s[start..i]);
                start = i + 1;
            }
            _ => {}
        }
    }
    parts.push(&s[start..]);
    parts
}

fn parse_cli_arg(s: &str) -> interpreter::Value {
    // Bracketed list: [1,2,3], ["apple","ant"], [[1,2],[3,4]] or [] — split
    // top-level commas, honoring quoted strings so commas inside strings don't
    // split, and recursing into nested brackets.
    if s.starts_with('[') && s.ends_with(']') {
        let inner = s[1..s.len() - 1].trim();
        if inner.is_empty() {
            return interpreter::Value::List(std::sync::Arc::new(vec![]));
        }
        let items: Vec<interpreter::Value> = split_top_level_commas(inner)
            .into_iter()
            .map(|part| parse_cli_arg(part.trim()))
            .collect();
        return interpreter::Value::List(std::sync::Arc::new(items));
    }
    // Quoted string: strip surrounding double quotes and treat as text.
    // This preserves the raw contents (no escape decoding) which mirrors how
    // the rest of the CLI passes bare text.
    if s.len() >= 2 && s.starts_with('"') && s.ends_with('"') {
        return interpreter::Value::Text(std::sync::Arc::new(s[1..s.len() - 1].to_string()));
    }
    // Bare comma list: 1,2,3
    if s.contains(',') {
        let items: Vec<interpreter::Value> = split_top_level_commas(s)
            .into_iter()
            .map(|part| parse_cli_arg(part.trim()))
            .collect();
        return interpreter::Value::List(std::sync::Arc::new(items));
    }
    if s == "nil" {
        return interpreter::Value::Nil;
    }
    if let Ok(n) = s.parse::<f64>()
        && n.is_finite()
    {
        return interpreter::Value::Number(n);
    }
    if s == "true" {
        interpreter::Value::Bool(true)
    } else if s == "false" {
        interpreter::Value::Bool(false)
    } else {
        interpreter::Value::Text(std::sync::Arc::new(s.to_string()))
    }
}

/// Parse a single CLI arg, taking the declared param type into account.
///
/// For `Type::Text` params, the raw CLI string is kept verbatim as `Text`,
/// bypassing the greedy number/bool/list/nil parsing that `parse_cli_arg`
/// would otherwise perform. This prevents silent type drift where a function
/// declared as `arg:t` receives a `Number` at runtime because the CLI value
/// happened to look numeric (e.g. `"2"`), which then breaks `num arg` /
/// pattern-matches that key off the declared text type.
///
/// For every other declared type (or when no type is known), behaviour is
/// identical to `parse_cli_arg`.
fn parse_cli_arg_for_param(s: &str, expected: Option<&ast::Type>) -> interpreter::Value {
    if matches!(expected, Some(ast::Type::Text)) {
        // Preserve the raw CLI string verbatim. We still honor the surrounding
        // double-quote convention `parse_cli_arg` uses (callers sometimes pass
        // `"hello"` to force the text branch when no type info was available);
        // stripping them keeps quoted callers backward-compatible. Everything
        // else, *including* digits, `true`/`false`, `nil`, `[...]`, is kept
        // as-is and becomes `Text`.
        let stripped = if s.len() >= 2 && s.starts_with('"') && s.ends_with('"') {
            &s[1..s.len() - 1]
        } else {
            s
        };
        return interpreter::Value::Text(std::sync::Arc::new(stripped.to_string()));
    }
    parse_cli_arg(s)
}

/// Look up a function's declared parameter types in the program.
/// Returns `None` if the function isn't declared (e.g. inline-snippet entry).
fn lookup_param_types<'a>(
    program: &'a ast::Program,
    func_name: Option<&str>,
) -> Option<&'a [ast::Param]> {
    let name = func_name?;
    program.declarations.iter().find_map(|d| match d {
        ast::Decl::Function {
            name: n, params, ..
        } if n == name => Some(params.as_slice()),
        _ => None,
    })
}

/// Parse and coerce CLI args against a function's declared parameter types.
///
/// - For `Type::Text` params, the raw CLI string is preserved as `Text`
///   without any numeric/bool/list/nil coercion. This is the canonical fix
///   for the silent `t`-param coercion bug (a CLI input of `"2"` against
///   `arg:t` used to produce `Number(2.0)`).
/// - For `Type::List(_)` params, a non-list value is wrapped as `[value]`.
/// - All other params parse via `parse_cli_arg`'s standard rules.
fn parse_cli_args_typed(
    program: &ast::Program,
    func_name: Option<&str>,
    raw: &[String],
) -> Vec<interpreter::Value> {
    let params = lookup_param_types(program, func_name);
    raw.iter()
        .enumerate()
        .map(|(i, s)| {
            let expected = params.and_then(|ps| ps.get(i)).map(|p| &p.ty);
            let mut v = parse_cli_arg_for_param(s, expected);
            if matches!(expected, Some(ast::Type::List(_)))
                && !matches!(&v, interpreter::Value::List(_))
            {
                v = interpreter::Value::List(std::sync::Arc::new(vec![v]));
            }
            v
        })
        .collect()
}

/// Coerce CLI args to match a function's parameter types.
/// - Wraps a non-list value in `[value]` when the param type is `L _`
///
/// Superseded in production by `parse_cli_args_typed`, which combines parsing
/// and coercion in one type-aware pass. Kept under `#[cfg(test)]` because the
/// existing test cases still pin the list-wrap behaviour cleanly when starting
/// from pre-parsed `Value`s; the typed counterparts cover the new from-raw
/// path. New non-test callers should use `parse_cli_args_typed`.
#[cfg(test)]
fn coerce_cli_args(
    program: &ast::Program,
    func_name: Option<&str>,
    mut args: Vec<interpreter::Value>,
) -> Vec<interpreter::Value> {
    let Some(params) = lookup_param_types(program, func_name) else {
        return args;
    };
    for (i, param) in params.iter().enumerate() {
        if i >= args.len() {
            break;
        }
        if matches!(&param.ty, ast::Type::List(_))
            && !matches!(&args[i], interpreter::Value::List(_))
        {
            args[i] = interpreter::Value::List(std::sync::Arc::new(vec![args[i].clone()]));
        }
    }
    args
}

