    // ── collect_hints: alias hint ─────────────────────────────────────────────

    #[test]
    fn collect_hints_alias_word_produces_hint() {
        // Use a known alias: "length" maps to "len" (or similar)
        // We need a word that ast::resolve_alias recognizes.
        // "add" → "+" or similar may exist. Let's use a known one.
        // From the spec: "length" → "len", "append" → "push" etc.
        // Try a few candidates that are likely aliases.
        let hints = collect_hints("f xs:L n>n;length xs");
        // If "length" is a known alias, we get a hint; otherwise we get none.
        // Just verify no panic.
        let _ = hints;
    }

    #[test]
    fn collect_hints_no_hints_when_clean() {
        let hints = collect_hints("f x:n>n;+x 1");
        assert!(hints.is_empty(), "clean code should have no hints");
    }

    // Regression: streaming-tail persona reported `hint: tail → tl` firing on
    // every Approach B run because the file path contained `tail`. The path
    // never reaches `collect_hints`, but the same root cause — raw-text scan
    // ignoring lexer boundaries — let alias words inside comments fire the
    // hint. These tests pin the lexer-token contract.
    #[test]
    fn collect_hints_alias_in_comment_does_not_fire() {
        // `tail` in a line comment must not trigger the alias hint.
        let hints = collect_hints("-- reading /tmp/ilo-streaming-tail-rerun/app.log\nf>n;42");
        assert!(
            hints.is_empty(),
            "alias word in comment should not fire hint, got: {:?}",
            hints
        );
    }

    #[test]
    fn collect_hints_other_alias_words_in_comments_do_not_fire() {
        // Spot-check a handful of common alias source words — none of these
        // should fire when they appear only in comments.
        for word in ["tail", "filter", "flatmap", "length", "head", "append"] {
            let src = format!("-- builtin: {word} something\nf>n;42");
            let hints = collect_hints(&src);
            assert!(
                hints.is_empty(),
                "comment-only `{}` should not fire hint, got: {:?}",
                word,
                hints
            );
        }
    }

    #[test]
    fn collect_hints_alias_in_string_does_not_fire() {
        // `tail` inside a string literal must not trigger the hint.
        let hints = collect_hints(r#"f>t;"tail of the file""#);
        assert!(
            hints.is_empty(),
            "alias word in string literal should not fire hint, got: {:?}",
            hints
        );
    }

    #[test]
    fn collect_hints_real_alias_use_still_fires() {
        // Contract: the hint *should* still fire when the alias appears as
        // a real source identifier. `tail` is a known alias for `tl`.
        let hints = collect_hints("f xs:L n>L n;tail xs");
        assert!(
            hints
                .iter()
                .any(|h| h.contains("`tail`") && h.contains("`tl`")),
            "expected tail→tl hint on real alias use, got: {:?}",
            hints
        );
    }

    #[test]
    fn collect_hints_double_equals_inside_comment_no_hint() {
        // `==` inside a comment shouldn't trigger the equality hint either.
        let hints = collect_hints("-- compare a == b here\nf x:n y:n>b;=x y");
        assert!(
            hints.is_empty(),
            "`==` inside comment should not fire hint, got: {:?}",
            hints
        );
    }

    // ── collect_hints: prefix-precedence trap ─────────────────────────────────
    //
    // Personas (logs-forensics across three rerun sessions) consistently
    // misread `*/a b c` as `(a*b)/c` when the parser actually produces
    // `(a/b)*c`. These tests pin the diagnostic firing on the four
    // same-precedence prefix-pair shapes and NOT firing on:
    //   * same-op repeats (`+*` → handled but `++` matches LTR intuition)
    //   * infix-position uses (`x*/y` would be a parse error anyway, but
    //     `a*b/c` where `*` is infix must NOT fire)
    //   * different-precedence pairs (`+*a b c` matches LTR intuition)
    //   * the swap form itself (`/*a b c` would still fire — both shapes
    //     are equally surprising, so both get the hint with the right swap
    //     suggestion).

    fn has_prefix_trap_hint(hints: &[String]) -> bool {
        hints
            .iter()
            .any(|h| h.contains("inner prefix op binds first"))
    }

    #[test]
    fn collect_hints_mul_div_prefix_pair_fires() {
        let hints = collect_hints("f a:n b:n c:n>n;*/a b c");
        assert!(
            has_prefix_trap_hint(&hints),
            "expected prefix-trap hint on `*/a b c`, got: {:?}",
            hints
        );
        let hint = hints
            .iter()
            .find(|h| h.contains("inner prefix op binds first"))
            .unwrap();
        assert!(
            hint.contains("(a/b)*c"),
            "hint should state actual parse, got: {hint}"
        );
    }

    #[test]
    fn collect_hints_div_mul_prefix_pair_fires() {
        let hints = collect_hints("f a:n b:n c:n>n;/*a b c");
        assert!(
            has_prefix_trap_hint(&hints),
            "expected prefix-trap hint on `/*a b c`, got: {:?}",
            hints
        );
    }

    #[test]
    fn collect_hints_plus_minus_prefix_pair_fires() {
        let hints = collect_hints("f a:n b:n c:n>n;+-a b c");
        assert!(
            has_prefix_trap_hint(&hints),
            "expected prefix-trap hint on `+-a b c`, got: {:?}",
            hints
        );
    }

    #[test]
    fn collect_hints_minus_plus_prefix_pair_fires() {
        let hints = collect_hints("f a:n b:n c:n>n;-+a b c");
        assert!(
            has_prefix_trap_hint(&hints),
            "expected prefix-trap hint on `-+a b c`, got: {:?}",
            hints
        );
    }

    #[test]
    fn collect_hints_same_op_repeat_does_not_fire() {
        // `++a b c` parses as `(a+b)+c` which IS the left-to-right reading.
        // No hint should fire — addition is associative and same-op repeats
        // don't trip the intuition.
        let hints = collect_hints("f a:n b:n c:n>n;++a b c");
        assert!(
            !has_prefix_trap_hint(&hints),
            "same-op repeat should not fire prefix-trap hint, got: {:?}",
            hints
        );
        // Also `**a b c`.
        let hints = collect_hints("f a:n b:n c:n>n;**a b c");
        assert!(!has_prefix_trap_hint(&hints));
    }

    #[test]
    fn collect_hints_different_precedence_pair_does_not_fire() {
        // `+*a b c` is the canonical example from SPEC.md: `(a*b)+c`. Matches
        // left-to-right intuition because multiplication binds tighter, so
        // a human reading `+ * a b c` mentally inserts the multiplication
        // first anyway. No hint.
        let hints = collect_hints("f a:n b:n c:n>n;+*a b c");
        assert!(
            !has_prefix_trap_hint(&hints),
            "different-precedence pair should not fire prefix-trap hint, got: {:?}",
            hints
        );
        // `*+a b c` → `*(+a b) c == (a+b)*c`. Multiplication being outer with
        // addition inner does match how a human reads `* + a b c` (add first,
        // then multiply), so still no hint.
        let hints = collect_hints("f a:n b:n c:n>n;*+a b c");
        assert!(!has_prefix_trap_hint(&hints));
    }

    #[test]
    fn collect_hints_infix_arith_does_not_fire() {
        // `a*b/c` is infix, not prefix. The `*` and `/` are not adjacent in
        // the token stream (an Ident sits between them), so the pattern
        // doesn't match.
        let hints = collect_hints("f a:n b:n c:n>n;a*b/c");
        assert!(
            !has_prefix_trap_hint(&hints),
            "infix `a*b/c` should not fire prefix-trap hint, got: {:?}",
            hints
        );
    }

    #[test]
    fn collect_hints_prefix_op_after_assign_fires() {
        // `r=*/a b c` has the trap pair at a prefix position (after `=`).
        let hints = collect_hints("f a:n b:n c:n>n;r=*/a b c;r");
        assert!(
            has_prefix_trap_hint(&hints),
            "prefix-trap after `=` should fire, got: {:?}",
            hints
        );
    }

    #[test]
    fn collect_hints_op_pair_after_value_does_not_fire() {
        // Pathological shape: `x*/y` is a parse error, but if it tokenises
        // as `Ident Star Slash Ident`, the `Star` is in infix position (its
        // predecessor `x` is value-yielding), so we don't fire. Pin that the
        // predecessor check rules out non-prefix uses.
        // We can't actually run this through collect_hints with a valid
        // program, but the unit-level shape is exercised by infix test above.
        // This test pins behaviour for the standalone detector.
        use lexer::Token::*;
        let tokens = vec![
            (Ident("x".to_string()), 0..1),
            (Star, 1..2),
            (Slash, 2..3),
            (Ident("y".to_string()), 3..4),
        ];
        assert!(
            detect_prefix_precedence_trap(&tokens).is_none(),
            "trap detector must not fire when op pair follows a value"
        );
    }

    #[test]
    fn collect_hints_minus_followed_by_number_no_match() {
        // `*-5 b c` lexes as `Star Number(-5) Ident Ident` (greedy negative
        // literal). The `Minus` is absorbed into the number, so the prefix
        // pair `Star Minus` never appears. This is by design — a numeric
        // literal isn't ambiguous, so no hint needed.
        let hints = collect_hints("f b:n c:n>n;*-5 b c");
        assert!(
            !has_prefix_trap_hint(&hints),
            "negative literal should not be misread as prefix-pair, got: {:?}",
            hints
        );
    }

    #[test]
    fn collect_hints_minus_with_space_does_fire() {
        // `*- 5 b c` (with space) lexes as `Star Minus Number Ident Ident`,
        // which IS a real prefix pair. Same trap, same hint.
        // Note: tokens are `Star Minus Number(5) Ident(b) Ident(c)` — the
        // value-yielding-token check looks at the predecessor of `Star`,
        // which in this fragment is start-of-input. So the hint should fire.
        use lexer::Token::*;
        let tokens = vec![
            (Star, 0..1),
            (Minus, 1..2),
            (Number(5.0), 3..4),
            (Ident("b".to_string()), 5..6),
            (Ident("c".to_string()), 7..8),
        ];
        // The (Star, Minus) pair isn't in our four target shapes
        // ({*,/} and {+,-}), so it should NOT fire — `*` and `-` are
        // different precedence. Verify.
        assert!(detect_prefix_precedence_trap(&tokens).is_none());
    }

    #[test]
    fn collect_hints_paren_grouped_prefix_pair_does_not_fire() {
        // The parenthesised form `(/ *errs 100 tot)` is the canonical
        // disambiguation — the hint itself recommends grouping. Flagging it
        // would contradict the advice and spam every rate-calc program.
        // Streaming-tail rerun4 friction: bare `(/ *errs 100 tot)` should
        // be silent.
        let hints = collect_hints("f errs:n tot:n>n;(/ *errs 100 tot)");
        assert!(
            !has_prefix_trap_hint(&hints),
            "parenthesised prefix pair `(/ *errs 100 tot)` should not fire prefix-trap hint, got: {:?}",
            hints
        );
        // All four pair shapes should be suppressed inside parens.
        for src in [
            "f a:n b:n c:n>n;(*/ a b c)",
            "f a:n b:n c:n>n;(/* a b c)",
            "f a:n b:n c:n>n;(+- a b c)",
            "f a:n b:n c:n>n;(-+ a b c)",
        ] {
            let hints = collect_hints(src);
            assert!(
                !has_prefix_trap_hint(&hints),
                "paren-grouped pair in `{src}` should be silent, got: {:?}",
                hints
            );
        }
    }

    #[test]
    fn collect_hints_nested_parens_prefix_pair_does_not_fire() {
        // Nested parens: predecessor of op1 is still `LParen`, so suppression
        // applies. Pins that the immediate-predecessor check is sufficient.
        let hints = collect_hints("f a:n b:n c:n>n;((*/ a b c))");
        assert!(
            !has_prefix_trap_hint(&hints),
            "doubly-parenthesised pair should be silent, got: {:?}",
            hints
        );
    }

    #[test]
    fn collect_hints_bare_prefix_pair_still_fires_after_paren_suppression() {
        // Regression-safety: the bare unparenthesised form must still fire.
        // The suppression only kicks in on `LParen` predecessor, not on a
        // generic non-value-yielding token.
        let hints = collect_hints("f a:n b:n c:n>n;*/a b c");
        assert!(
            has_prefix_trap_hint(&hints),
            "bare `*/a b c` must still fire after paren-suppression added, got: {:?}",
            hints
        );
    }

    #[test]
    fn collect_hints_paren_grouped_pair_unit_check() {
        // Unit-level pin on the detector: `LParen Star Slash Ident Ident Ident RParen`
        // must return `None`.
        use lexer::Token::*;
        let tokens = vec![
            (LParen, 0..1),
            (Star, 1..2),
            (Slash, 2..3),
            (Ident("a".to_string()), 4..5),
            (Ident("b".to_string()), 6..7),
            (Ident("c".to_string()), 8..9),
            (RParen, 9..10),
        ];
        assert!(
            detect_prefix_precedence_trap(&tokens).is_none(),
            "detector must suppress when immediate predecessor is LParen"
        );
    }

